insert into public.cartas (color, tipo, texto, flavor) values
  ('roja', 'Personajes', 'El Pollo Brito', 'El hombre que es capaz de meterle un solo de cuatro y un "¡Epa!" a cualquier canción del mundo, incluyendo el reguetón más oscuro o una de Metallica.'),
  ('roja', 'Personajes', 'Nagueboná, Vladimir', 'El reclamo viral que repetimos sin saber bien por qué'),
  ('roja', 'Personajes', 'Miguel Cabrera', 'Un señor que batea pelotazos a 400 pies de distancia en el imperio pero que celebra los triunfos con un flow de malandro de Maracay'),
  ('roja', 'Personajes', 'El Gocho', 'El ser más trabajador, amable y respetuoso del país, hasta que maneja un camión de verduras bajando la autopista a 120 km/h sin frenos.'),
  ('roja', 'Personajes', 'El Valenciano', 'Ciudadano de la capital del "Epa, pana". Se rumorea que nacen con una camisa de marca y un odio natural hacia los caraqueños.'),
  ('roja', 'Personajes', 'El Caraqueño', 'Alguien que cree que después de los túneles de Tazón todo lo demás es "monte y culebra", aunque sufre tres horas de cola para comprar pan.'),
  ('roja', 'Personajes', 'El Oriental', 'Todo es ''a la orden, vale''; vive entre playa, pesca y relax'),
  ('roja', 'Personajes', 'El Maracucho', 'El único ser humano capaz de usar el "¡Qué molleja!" como sustantivo, verbo, adjetivo y declaración de guerra, todo bajo un calor de 42°C.'),
  ('roja', 'Personajes', 'Maite Delgado', 'El estándar de elegancia nacional. Si ella no dice "¡Buenas noches, Poliedro!", el evento simplemente no cuenta.'),
  ('roja', 'Personajes', 'Deyna Castellanos', 'La mujer que demostró que en Venezuela el fútbol también se juega con clase, tacos y goles de media cancha que dejan a los hombres llorando.'),
  ('roja', 'Personajes', 'El bachaquero de la esquina', 'Un economista empírico que no estudió en Harvard, pero te calcula el cambio del dólar flotante, paralelo y del futuro en tres segundos.'),
  ('roja', 'Espanto', 'El Silbón', 'Un gigantón con complejo de músico frustrado que carga un saco de huesos. Si lo escuchas lejos, corre a rezar; si lo escuchas cerca... bueno, ya no importa.'),
  ('roja', 'Espanto', 'La Sayona', 'La pesadilla de los hombres infieles.'),
  ('roja', 'Espanto', 'La Loca Luz Caraballo', 'El personaje andino que perdió la cuenta de los hijos y la cordura. La excusa perfecta que usan tus amigos cuando andas buscando algo y no lo encuentras.'),
  ('roja', 'Personajes', 'El Doctor Knoche', 'El mismísimo Dr. Frankenstein del Ávila.'),
  ('roja', 'Personajes', 'Ánima del Purgatorio', 'A la que le prenden una vela para que cuide el carro o ayude a pasar el examen. Eso sí, si le quedas mal, te jala las patas a medianoche.'),
  ('roja', 'Dichos', '"Quedar como novia de pueblo"', 'El estado máximo de la decepción. Vestido, alborotado y esperando en la plaza por algo que obviamente nunca iba a llegar.'),
  ('roja', 'Dichos', '"Ponerse las alpargatas"', 'El aviso oficial de que la situación se puso color de hormiga. Porque lo que viene no es joropo, es rock pesado.'),
  ('roja', 'Dichos', '"Echarle Bolas"', 'El acto heroico de trabajar duro contra todo pronóstico, la luz, el agua y CANTV, con una sonrisa en la cara.'),
  ('roja', 'Dichos', '"Más perdido que el hijo de Lindbergh"', '¿El hijo de quien?'),
  ('roja', 'Dichos', '"Matar un tigre"', 'El arte de la supervivencia económica. Hacer tres trabajos extra que no tienen nada que ver con tu profesión para poder llegar a la quincena.'),
  ('roja', 'Comida', 'Un perro caliente "Con Todo" a las 3:00 a.m.', 'Una obra de arte de la ingeniería callejera que desafía las leyes de la gravedad y de la digestión. Lleva repollo, papitas y 14 salsas misteriosas.'),
  ('roja', 'Comida', 'La empanada "Operada"', 'Una empanada normal a la que abren a la mitad sin piedad para meterle queso, carne, tajada y todo lo que quepa. Ingeniería pura.'),
  ('roja', 'Comida', 'Queso guayanés derretido', 'El único material en el universo capaz de estirarse desde la mesa hasta la boca de tu vecino sin romperse.'),
  ('roja', 'Comida', 'Una arepa de "Dominó"', 'La combinación perfecta de caraotas negras y queso blanco. Deliciosa para el paladar, peligrosa para los que duermen contigo esa noche.'),
  ('roja', 'Comida', 'El "Pegao" de la olla de arroz', 'El oro crujiente del fondo de la olla por el cual los hermanos menores están dispuestos a batirse a duelo con cucharas de palo.'),
  ('roja', 'Musica', 'Mercedes', 'El cuento de la vaca que se metió en el caño por floja y el caimán la agarró. La metáfora venezolana perfecta para el que se busca sus propios problemas.'),
  ('roja', 'Musica', 'Venezuela', 'El himno sentimental que hace llorar instantáneamente a cualquier venezolano que esté a más de 50 kilómetros de la frontera.'),
  ('roja', 'Musica', 'El Alma Llanera', 'La señal internacional de que la fiesta SE ACABÓ. Si suena esto, recoge tus cosas, busca tus zapatos y vete, porque van a prender las luces blancas.'),
  ('roja', 'Musica', '1 y 1 es igual a 3', 'El himno oficial del infiel arrepentido que intenta usar matemáticas creativas para explicar por qué lo vieron con otra en el centro comercial.'),
  ('roja', 'Musica', 'Llorarás', 'La canción que te hace bailar salsa aunque tengas dos pies izquierdos y estés sufriendo por un amor que te dejó limpio.'),
  ('roja', 'Musica', 'El "Cumpleaños Feliz"', 'La tortura psicológica de 15 minutos donde te cantan cuatro canciones distintas, te meten el "ay, qué noche tan preciosa" y terminas con dolor de aplaudir.'),
  ('roja', 'Guachafitas', '"Al fondo hay puesto"', 'La mentira más grande del transporte público. El "fondo" no existe, es una dimensión desconocida donde la gente viaja flotando.'),
  ('roja', 'Guachafitas', 'Un "bajón" de luz justo cuando vas a guardar la tesis', 'El microinfarto nacional. El momento exacto donde ves la pantalla negra y recuerdas que no habías apretado "Control + G" desde 2023.'),
  ('roja', 'Personajes', 'La tía que te manda cadenas de Piolín por WhatsApp', 'Tu dosis diaria de "Bendiciones, sobrino" acompañada de un GIF brillante que pesa 45 megabytes y te colapsa la memoria del teléfono.'),
  ('roja', 'Guachafitas', 'El "Vuelto" en caramelos', 'La moneda de curso legal impuesta por los comercios. Nadie sabe cuántos mentados de menta equivalen a un dólar, pero todos los aceptamos.'),
  ('roja', 'Guachafitas', 'Un chisme en el trabajo', 'Información clasificada que corre más rápido que la fibra óptica de Cantv y que muta tres veces antes de llegar a la oficina del jefe.'),
  ('roja', 'Guachafitas', 'Quedarse sin agua a mitad del baño', 'El drama trágico caribeño. El instante en que descubres que el tanque falló y te toca buscar el tobito con los ojos cerrados.'),
  ('roja', 'Guachafitas', 'El pana que dice "Voy saliendo"', 'El manejo de la física cuántica del tiempo. Su "voy saliendo" significa que llegará en dos horas y probablemente oliendo a jabón recién usado.'),
  ('roja', 'Guachafitas', 'Juego de dominó un domingo por la tarde', 'Un deporte extremo donde se habla de política, se toma cerveza, se grita y se tranca la cochina con violencia dramática sobre la mesa.'),
  ('roja', 'Guachafitas', 'Motorizado esquivando la lluvia bajo un puente', 'Una convención espontánea de 40 personas con impermeables que trancan la autopista mientras esperan que pase la nube.'),
  ('roja', 'Guachafitas', 'El olor a tierra mojada cuando empieza mayo', 'La señal de la naturaleza de que preparen los tobos porque se viene el invierno (y las goteras del techo).'),
  ('roja', 'Personajes', 'La "Chola" de tu mamá', 'El único proyectil teledirigido del mundo que dobla las esquinas de la casa para impactar con precisión milimétrica en tu cabeza.'),
  ('roja', 'Evento', 'Un Caracas-Magallanes', 'El evento que divide familias, destruye noviazgos y paraliza al país por el simple placer de decirle al otro "llorón".'),
  ('roja', 'Personajes', 'El señor que vende helados en la playa', 'Un atleta de alto rendimiento que camina 15 kilómetros sobre la arena caliente cargando un cajón de anime mientras grita sin micrófono.'),
  ('roja', 'Guachafitas', '"Háblame, chamo"', 'El saludo universal que puede significar desde un cordial "buenos días" hasta un "estás en problemas y necesito que me expliques".'),
  ('roja', 'Objetos', 'Carro con los amortiguadores vencidos', 'Un vehículo que parece una licuadora andante y te hace sentir cada piedrita de la carretera directo en los riñones.'),
  ('roja', 'Guachafitas', 'El "Toque de queda" de la abuela', 'Las 9:00 p.m. Después de esa hora, si no estás en la casa, asume que estás en las noticias o que ya no formas parte de la familia.'),
  ('roja', 'Personajes', 'Lila Morillo', 'El verdadero misterio de la ciencia venezolana. Se rumorea que tiene el secreto de la eterna juventud y que sobrevivirá al fin del mundo junto a los coquitos.'),
  ('roja', 'Personajes', 'Er Conde del Guácharo', 'El embajador honorario de la "mamadera de gallo". Capaz de hacerte reír y ofenderte al mismo tiempo con una sola palabra de cuatro letras.'),
  ('roja', 'Personajes', 'Oscar D''León', 'El hombre que tiene más energía a las 3:00 a.m. que cualquier joven de 20 años después de tres cafés. ¡Sabroooso!'),
  ('roja', 'Comida', 'Una empanada de cazón en la playa', 'Manjar de los dioses que sabe mejor si viene acompañada de salsa de ajo, un chorrito de limón y moscas apuradas por probarla.'),
  ('roja', 'Comida', 'Una empanada de queso en la playa', 'Chamo, ¿de verdad?'),
  ('roja', 'Comida', 'La última papa frita del plato', 'El motivo real por el cual se han terminado grandes amistades y matrimonios en este país. Se mira, pero no se toca sin permiso.'),
  ('roja', 'Comida', 'Un Toddy bien frío', 'El abrazo en un vaso que cura el mal de amor, el cansancio y cualquier crisis existencial. Dejar los grumos arriba es ley.'),
  ('roja', 'Comida', 'Pirulín', 'La moneda de cambio emocional más valiosa del mercado. Si te regalan uno de los grandes, es amor verdadero.'),
  ('roja', 'Objetos', 'Un autobús con la música a todo volumen', 'Una discoteca móvil con olor a gasoil donde el chofer cree que está compitiendo en la Fórmula 1 y es el DJ al mismo tiempo.'),
  ('roja', 'Evento', 'La cola de la gasolina', 'El club social interactivo más grande del país. Donde juegas dominó, haces amigos para toda la vida y replanteas tu futuro a las 4:00 a.m.'),
  ('roja', 'Objetos', 'La calor Maracucha', 'Un fenómeno termodinámico que te hace sentir que estás caminando directamente sobre la superficie del sol, pero con un cepillao en la mano.'),
  ('roja', 'Evento', 'Bajón de luz', 'El enemigo silencioso que te hace saltar de la cama a las 2:00 a.m. a desenchufar la nevera como si fueras un experto en desactivar bombas.'),
  ('roja', 'Guachafitas', 'El "Te lo dije" de tu Mamá', 'La frase más temida, precisa y científicamente comprobada de la historia. Tiene un 100% de efectividad y duele más que un chancletazo.'),
  ('roja', 'Guachafitas', 'El "Ahorita"', 'Unidad de tiempo indeterminada que puede significar: en 5 minutos, en 3 horas, el próximo mes o, más probablemente, NUNCA.'),
  ('roja', 'Personajes', 'La sifrina', 'Habla con una papa en la boca y sufre si el lugar no tiene aire acondicionado. Jura que es de la realeza, pero se le va la luz igual que a ti.'),
  ('roja', 'Personajes', '"Malandro" de cartón', 'Camina de lado, habla grueso y dice que domina la zona, pero cuando escucha un triquitraqui sale corriendo a esconderse detrás de su mamá.'),
  ('roja', 'Personajes', 'Sugar daddy', 'Un señor con canas y billetera gorda cuyo único superpoder real es pasar la tarjeta de crédito sin mirar el monto en el punto de venta.'),
  ('roja', 'Personajes', 'La tía evangélica y chismosa', 'Te dice que vas directo al infierno por tus tatuajes y tus salidas los viernes, pero se sabe la vida íntima de todos los vecinos de la cuadra.'),
  ('roja', 'Personajes', 'El pana que se cree influencer', 'Graba historias mostrando los músculos en el gimnasio, tiene 200 seguidores y le pide prestado al papá para pagar la cuenta.'),
  ('roja', 'Personajes', 'La bendecida y afortunada', 'Modelo de redes sociales que viaja a playas exóticas "trabajando duro". Su mayor esfuerzo laboral es posar al lado de un señor de 70 años.'),
  ('roja', 'Personajes', 'Maracucho picado', 'Un volcán andante de groserías regionales. Capaz de insultar a tus ancestros solo porque le dijiste que en su ciudad hace mucho calor.'),
  ('roja', 'Personajes', 'Gocho despechado', 'El peligro hecho ternura. Se toma una botella de licor artesanal, llora con música llanera y llama a la ex a las 3:00 a.m. para pedirle perdón cantadito.'),
  ('roja', 'Personajes', 'La arrecha de barrio', 'El ser más peligroso del planeta si le quitan el puesto en la cola. Te arma un escándalo que incluye desprendimiento de uñas y pérdida de dignidad.'),
  ('roja', 'Personajes', 'El sabelotodo de la familia', 'Ese tío que opina de política, medicina, mecánica y física cuántica con la misma seguridad con la que se toma el tercer ron de la tarde.'),
  ('roja', 'Personajes', 'Amigo de lo ajeno', 'Ese personaje que te pide un cigarro, un trago o una empanada y termina consumiéndose la mitad de tus provisiones con toda la frescura del mundo.'),
  ('roja', 'Personajes', 'El vecino fastidioso del condominio', 'El que pasa el día vigilando quién deja la basura fuera de lugar o quién hace ruido a las 8:01 p.m. para poner la queja en el grupo de WhatsApp.'),
  ('roja', 'Personajes', 'La que no rompe un plato', 'Cara de ángel que va a misa los domingos, pero en las fiestas se toma hasta el agua de los floreros y se besa con tres amigos en la misma noche.'),
  ('roja', 'Personajes', 'La tóxica', 'Tu ex revisando tus historias de Instagram desde un perfil creado hace cinco minutos con la foto de un perrito tierno.'),
  ('roja', 'Personajes', 'El duende que te esconde las llaves', 'Un ser maligno que habita en todas las casas. Hace que las llaves desaparezcan y luego aparezcan mágicamente en el mismo lugar donde ya buscaste diez veces.'),
  ('roja', 'Dichos', '"Gastar pólvora en zamuro"', 'El acto inútil de intentar enamorar a esa persona que sabes perfectamente que se escribe con medio planeta y no te va a parar ni media bola.'),
  ('roja', 'Dichos', '"Chivo que se devuelve se esnuca"', 'La ley de oro de la mala junta. Si ya dijiste que te ibas a tomar la última fría, te la tomas; arrepentirse a última hora es de cobardes.'),
  ('roja', 'Dichos', '"Morder el peine"', 'Caer redondito en la trampa de tu pareja cuando te pregunta de forma inocente: "Mi amor, ¿quién es esa persona que te dio ''me gusta''?"'),
  ('roja', 'Guachafitas', 'Sacar el culo', 'El arte de la evasión cuando ves venir de lejos al conocido fastidioso que siempre te pide dinero prestado o quiere que le hagas un favor gratis.'),
  ('roja', 'Objetos', 'El "rompe colchón"', 'Un cóctel de mariscos que promete propiedades afrodisíacas milagrosas, pero que por lo general solo te garantiza pasar tres días metido en el baño.'),
  ('roja', 'Objetos', 'La salsita de ajo sospechosa del carrito callejero', 'Tiene tres días fuera de la nevera bajo el sol, pero le da ese sabor adictivo que te hace volver a pesar del riesgo de tifoidea.'),
  ('roja', 'Objetos', 'Anís con yogurt de fresa', 'La bebida oficial de las plazas públicas. Una mezcla satánica que sabe a jarabe para la tos pero te borra la memoria en media hora.'),
  ('roja', 'Objetos', 'Una chicha con exceso de leche condensada', 'Un cemento estomacal tan denso y dulce que te drena la energía y te obliga a dormir una siesta de cinco horas.'),
  ('roja', 'Objetos', 'Sopa de mondongo con pata de vaca', 'Un caldo espeso capaz de revivir a un muerto por resaca o de matar a un vivo por indigestión fulminante.'),
  ('roja', 'Objetos', 'El guayoyo amargo de oficina', 'Un café que parece agua de paraguas, hecho con la colada del día anterior, que solo sirve para mantenerte alterado y con acidez.'),
  ('roja', 'Objetos', 'Vallenato cortavenas a las 4:00 a.m.', 'El detonante definitivo para que los hombres barbudos empiecen a llorar, abracen a sus amigos y llamen a la ex diciendo "te extraño".'),
  ('roja', 'Personajes', 'Sandy y Papo', 'La música que despierta los instintos de baile prohibidos en cualquier tía de más de 50 años en medio de la sala, "Eh Eh, es hora de bailar".'),
  ('roja', 'Objetos', 'Reguetón viejo (2006)', 'Ese que saca tu lado más alegre y te hace olvidar por completo que tienes un título universitario y dos diplomados.'),
  ('roja', 'Objetos', 'La hora loca', 'El momento exacto donde la elegancia de la fiesta se va al demonio y el cumpleañero termina gateando con una corbata amarrada en la frente.'),
  ('roja', 'Objetos', 'Salsa brava', 'Música que te hace bailar en una "baldoza" y te da una excusa para abrazar a tu pareja de turno.'),
  ('roja', 'Objetos', 'El "visto" azul de WhatsApp', 'Esos diez minutos de silencio sepulcral donde revisas si todavía tienes pulso mientras esperas a ver si te mandan a lavarte ese culo.'),
  ('roja', 'Guachafitas', 'Tarjeta rechazada por fondos insuficientes', 'El momento más humillante de la existencia humana. Deseas que la tierra se abra y te trague junto con el código 51.'),
  ('roja', 'Evento', 'Quedarse sin papel tualé en baño ajeno', 'El drama existencial donde revisas desesperadamente el basurero, el rollo vacío y terminas sacrificando una media.'),
  ('roja', 'Evento', 'Ir a un motel y encontrarte un conocido', 'Una situación de alta tensión donde ambos se miran a través del parabrisas y firman un pacto implícito de silencio absoluto.'),
  ('roja', 'Personajes', 'El mecánico', 'Un cirujano automotriz que le cambia un tornillo a tu carro, te habla con términos inventados y te deja limpio por los próximos tres meses.'),
  ('roja', 'Personajes', 'La reunión de condominio', 'El evento anual donde los vecinos decentes se transforman en gladiadores romanos por culpa de una filtración o de una mascota inquieta.'),
  ('roja', 'Personajes', 'El conocido que te invita a "ser tu propio jefe"', 'Un estafador piramidal con traje alquilado que te cita en un café para explicarte cómo ganar millones vendiendo batidos o monedas virtuales.'),
  ('roja', 'Evento', 'Revisar el teléfono de tu pareja mientras se baña', 'Un deporte extremo no apto para cardíacos. Sabes que el que busca encuentra, pero igual ahí estás tú intentando adivinar la clave.'),
  ('roja', 'Evento', 'Hacerse el dormido en el autobús para no dar el puesto', 'Un acto de bajeza moral donde ensayas tu mejor cara de coma profundo mientras sientes la mirada juzgadora de todo el colectivo.'),
  ('roja', 'Objetos', 'Un piropo de albañil con exceso de creatividad', 'Una construcción poética callejera tan explícita y ordinaria que te hace dudar de si te están halagando o te están amenazando.'),
  ('roja', 'Personajes', 'El pana que se vuelve insoportable con dos tragos', 'Pasa de ser un tipo tranquilo a querer pelear con el mesonero, romper un vaso y confesarle su amor a la novia de su mejor amigo.'),
  ('roja', 'Personajes', 'El parquero de la calle', 'Un guía que solo aparece cuando vas a arrancar para pedirte una colaboración por haber visto cómo chocabas contra el poste.'),
  ('roja', 'Evento', '"A la derecha ciudadano"', 'El momento donde sudas frío, te acuerdas de todos tus pecados y rezas para que no se den cuenta de que tienes el documento vencido.'),
  ('roja', 'Evento', 'Comer caraotas tres días seguidos', 'Una decisión gastronómica deliciosa que se convierte en una bomba de tiempo si tienes una reunión en una oficina pequeña con aire acondicionado.'),
  ('roja', 'Objetos', 'La rumba en el estacionamiento de una licorería', 'Abrir la maleta del carro, poner la música a todo volumen, tomar de un vaso plástico y creerse el dueño del mundo hasta que llega la patrulla.'),
  ('roja', 'Objetos', 'Un tatuaje barato hecho en una sala', 'Una obra de arte que se suponía era un león imponente y terminó pareciendo un gato desnutrido con mala actitud.'),
  ('roja', 'Objetos', 'Mudanza hecha en el techo de un carro pequeño', 'Amarrar una nevera, una lavadora y dos colchones con un solo mecate y subir la autopista rezándole a todos los santos.'),
  ('roja', 'Objetos', 'El pre-despacho antes de ir a la discoteca', 'Tomarse media botella de ron barato en la sala de tu casa para no gastar adentro, y llegar tan borracho que el portero no te deja entrar.'),
  ('roja', 'Evento', 'Ya te hice la transferencia, debe estar por caer', 'La estafa digital más usada para ganar unas horas de paz con el cobrador mientras consigues el dinero de verdad.'),
  ('roja', 'Personajes', 'El gordito del grupo que siempre tiene calor', 'Un pana que suda como tapa de olla de presión a los dos minutos de apagar el aire acondicionado y te suplica que prendas el ventilador.'),
  ('roja', 'Objetos', 'Un dolor de barriga repentino en plena calle', 'La verdadera prueba de fe. Cuando tienes que usar todo tu control mental y espiritual para no pasar una vergüenza histórica en la avenida.'),
  ('roja', 'Evento', 'Ir a la playa y que llueva a los cinco minutos', 'La salazón astronómica que arruina el viaje, te moja las empanadas y te obliga a regresarte lleno de arena y frustración.'),
  ('roja', 'Objetos', 'El último trago', 'Ese vaso misterioso que te tomas a las 5:00 a.m. y te hace prometerle a Dios que más nunca vuelves a tocar el alcohol.'),
  ('roja', 'Personajes', 'Eladio Lárez', 'El caballero de la televisión. Un señor tan elegante y correcto que juras que duerme en traje y que te mira con decepción si fallas una pregunta tonta. "¿Estás seguro?"'),
  ('roja', 'Personajes', 'Valentina Quintero', 'La mujer que ha dormido en todas las posadas y ha comido empanada en todas las carreteras del mapa. si dice que un rancho con piso de tierra es "espectacular", tú vas con los ojos cerrados.'),
  ('roja', 'Personajes', 'Osmel Sousa', 'El hombre que destruyó la autoestima de tres generaciones de mujeres con solo mirarlas de arriba a abajo.'),
  ('roja', 'Personajes', 'Gilberto Correa', 'La voz oficial de las borracheras elegantes del Poliedro. El señor tenía tanta clase que podía anunciar que venía el fin del mundo y tú aplaudías pensando que era una atracción internacional de Sábado Sensacional.'),
  ('roja', 'Personajes', 'Renny Ottolina', 'El fantasma al que todos invocan cuando quieren decir que "antes todo era mejor".'),
  ('roja', 'Personajes', 'Daniel Sarcos', 'El animador que basó toda su carrera en correr por el escenario, abrazar señoras mayores de la emoción y gritar "¡Guerra de los sexos!" a todo pulmón.'),
  ('roja', 'Personajes', 'Viviana Gibelli', 'La mujer que perfeccionó el arte de fingir demencia en televisión en vivo mientras lidiaba con hombres intensos, concursos absurdos de meter las manos en urnas con cucarachas y coreografías baratas.'),
  ('roja', 'Personajes', 'Mimí Lazo', 'La mujer que facturó millones enseñándole a las mujeres despechadas del país que la culpa de su infelicidad siempre es de un hombre sin oficio.'),
  ('roja', 'Personajes', 'Norkys Batista', 'Una mujer con un cuerpo espectacular pero con una boca que parece un callejón sin salida a las 3:00 a.m.'),
  ('roja', 'Personajes', 'Edgar Ramírez', 'El chamo que logró el milagro de salir de las novelas baratas de la tarde venezolana para terminar actuando con Robert De Niro.'),
  ('roja', 'Personajes', 'La mujer de Judas', 'El juego de terror psicológico más grande de la televisión. Tenías a seis viejas millonarias vestidas de novia matando gente a diestra y siniestra.'),
  ('roja', 'Personajes', 'Mi gorda bella', 'Agarraron a una actriz espectacular, la metieron en un traje de goma que parecía un muñeco de Michelin, y nos querían convencer de que nadie se daba cuenta del truco.'),
  ('roja', 'Personajes', 'Voltea pa'' que te enamores', 'La novela que convenció a las sifrinas de que era buena idea salir con el mecánico o el mototaxista de la esquina porque "el amor todo lo puede". Un peligro para la economía familiar.'),
  ('roja', 'Personajes', 'Yulimar Rojas', 'Una chama de dos metros que salta tan lejos que viola las leyes de la física y de la gravedad, mientras celebra rompiendo récords mundiales bailando salsa brava frente a los europeos estiraos.'),
  ('roja', 'Personajes', 'Salomón Rondón', 'El "Gladiador". Un tanque humano cuya única estrategia es chocar contra defensas uruguayos o brasileños como si fuera una buseta sin frenos bajando por la autopista Caracas-La Guaira.'),
  ('roja', 'Personajes', 'Juan Arango', 'El hombre que tenía un pacto con el diablo en la pierna izquierda.'),
  ('roja', 'Personajes', 'Greivis Vásquez', 'El chamo que llegó a la NBA metiendo puro "chalequeo" caribeño.'),
  ('roja', 'Personajes', 'Bob Abreu', '"El Comedulce". Un tipo tan relajado para jugar que parecía que estaba jugando béisbol en la playa con una cerveza en la mano, pero igual te metía un jonrón y te robaba la base en tus narices.'),
  ('roja', 'Personajes', 'Rubén Limardo', 'El carajito que se fue a Londres con una espada a ganarse una medalla de oro en esgrima (un deporte que en Venezuela solo se practica cuando te van a atracar con un cuchillo).'),
  ('roja', 'Personajes', 'Pastor Maldonado', 'El piloto de Fórmula 1 que convirtió las carreras de autos en un juego de carritos chocones de feria. Sabías que el chamo corría rápido, pero la apuesta real en el país era ver en qué vuelta se iba a estrellar.'),
  ('roja', 'Personajes', 'Simón Díaz', 'El único hombre capaz de cantarle a una vaca enferma o a un caballo viejo y hacer que un malandro de discoteca se ponga a llorar de la nostalgia en plena borrachera.'),
  ('roja', 'Personajes', 'Emilio Lovera', 'El hombre que tiene secuestradas todas las voces del país. Si Emilio Lovera se muere, nos quedamos sin el 90% de los personajes cómicos, locutores de radio y borrachos icónicos de la cultura pop.'),
  ('roja', 'Personajes', 'Ricardo Montaner', 'El cantautor que vive en una secta familiar gigante en Miami donde todos cantan, todos se visten igual y todos le dan las gracias a Dios por las regalías de las canciones de telenovela de los 90.'),
  ('roja', 'Personajes', 'Gustavo Dudamel', 'El director de orquesta que mueve las manos como si estuviera espantando un enjambre de avispas africanas mientras los sifrinos de Europa lo aplauden pensando que está interpretando a Beethoven con pasión caribeña.'),
  ('roja', 'Personajes', 'Dayana Mendoza', 'Una mujer tan absurdamente bella que hacía que las demás candidatas del Miss Universo parecieran las primas feas que invitas a la fiesta por obligación. Su nivel de perfección roza la ilegalidad.'),
  ('roja', 'Personajes', 'José Luis Rodríguez', 'El hombre del copete indestructible que se cambió de religión, cambió de familia y ahora vive en Miami dándole consejos espirituales a la gente.'),
  ('roja', 'Personajes', 'Servando y Florentino', 'Los hermanos que causaron que la mitad de las adolescentes de los 90 perdieran la virginidad mental (y real) en un concierto.'),
  ('roja', 'Personajes', 'Winston Vallenilla', 'El animador que vendió su alma al canal del Estado a cambio de poder gritar "¡Familiaaa!"'),
  ('roja', 'Personajes', 'Luis Chataing', 'Su negocio era burlarse de los políticos en la mañana para que la gente atrapada en la cola de la autopista se riera en vez de pegarse un tiro.'),
  ('roja', 'Personajes', 'Juan Gabriel en el Teresa Carreño', 'Un mexicano cantando despechos mientras los hombres más machistas del país lloraban abrazados tomando whisky de 18 años.'),
  ('roja', 'Personajes', 'Chino y Nacho', 'Dos chamos que empezaron cantando reguetón ordinario en las discotecas de Caracas y terminaron ganando Grammys en Miami'),
  ('roja', 'Personajes', 'Reinaldo Armas', 'El cantante de música llanera que tiene el récord nacional de haber musicalizado la mayor cantidad de borracheras con caña clara.'),
  ('roja', 'Personajes', 'La Vinotinto de las Eliminatorias', 'Una secta masoquista nacional basada en la frase "Mano, tengo fe".'),
  ('roja', 'Personajes', 'Leones del Caracas', 'Los fanáticos más insoportables del béisbol caribeño.'),
  ('roja', 'Personajes', 'Navegantes del Magallanes', 'La mitad del país que se viste de pavo real cada vez que le ganan un juego a Caracas.'),
  ('roja', 'Personajes', 'Roque Valero', 'El cantautor de los sifrinos despechados que pasó de cantar baladas lloronas en RCTV a ganarse un puesto en la asamblea política del gobierno por puro amor al presupuesto nacional.'),
  ('roja', 'Personajes', 'Jeremías', 'El cantante flojo que sacó un solo disco exitoso, inventó una teoría matemática absurda para justificar la infidelidad'),
  ('roja', 'Personajes', 'Hany Kauam', 'El cantautor con pinta de indigente chic que musicalizó todos los despechos de bachillerato en el 2007.'),
  ('roja', 'Personajes', 'Antonio Ledezma', '"¡SE ESTÁN LLEVANDO A LEDEZMA! ¡SE ESTÁN LLEVANDO A LEDEZMA!".'),
  ('roja', 'Personajes', 'Juan Guaidó', 'El presidente interino de Narnia.'),
  ('roja', 'Otros', 'Henrique Capriles', 'El eterno perdedor con gorra tricolor.'),
  ('roja', 'Otros', 'Diosdi', 'Si hablas paja, te va a tocar calarte el calabozo.'),
  ('roja', 'Otros', 'Chiave', 'Nadie sabe bien quién es, pero todos lo nombran'),
  ('roja', 'Otros', 'El Bigoton', 'Famoso por hablar con pajaritos que reencarnan'),
  ('roja', 'Personajes', 'Luis Aparicio', 'El único venezolano en el Salón de la Fama de Cooperstown con su número retirado por toda la MLB. Mientras tú no podías ni atrapar una bola en el patio.'),
  ('roja', 'Comida', 'La hallaca recalentada el 6 de enero', 'Cuando ya hasta el perro la mira con desprecio, pero igual te la comes porque botar comida es pecado mortal.'),
  ('roja', 'Objetos', 'La planta eléctrica del vecino', 'El símbolo de estatus del barrio: ruge a las 6 p.m. como un avión despegando y te recuerda que el rico de la cuadra cenará con luz mientras tú abanicas a los muchachos.'),
  ('roja', 'Lugares', 'El Ávila', 'El pulmón de Caracas y el único vecino que nunca se mudó, nunca se quejó del ruido y nunca pidió la cuota del condominio. Verde cuando llueve, amarillo cuando arde.'),
  ('roja', 'Evento', 'El apagón nacional de marzo', 'El día que el país entero descubrió que sin luz también se acaba el agua, el internet y la paciencia. Sacamos las velas como en tiempos de Bolívar.'),
  ('roja', 'Dichos', '"Echarle los perros"', 'El arte criollo de coquetear sin ninguna sutileza, como si la otra persona fuera una presa de caza y tú el sabueso más insistente del barrio.'),
  ('roja', 'Personajes', 'El buhonero de la avenida', 'Tiene un local más surtido que un centro comercial, pero cabe en una sábana que recoge en tres segundos cuando ve la policía.'),
  ('roja', 'Guachafitas', 'Bajarse del carro en plena cola a buscar la causa del trancón', 'El investigador privado nacional. Camina 200 metros, descubre que era una vaca acostada en el canal rápido y regresa a contar la novela.'),
  ('roja', 'Musica', 'La gaita zuliana sonando desde el 1° de octubre', 'El calendario venezolano no se rige por el clima ni por la luna: se rige por el momento en que el centro comercial pone a Maracaibo 15 a todo volumen aunque haga 38°C.'),
  ('roja', 'Espanto', 'La Llorona', 'La única señora que llora más fuerte que tu vecina cuando le suben el alquiler. Anda buscando a sus hijos por la quebrada y de paso te quita el sueño gratis.'),
  ('roja', 'Personajes', 'Andrés Galarraga', '''El Gran Gato'', que bateaba jonrones tan altos que todavía hay pelotas dando vueltas por la órbita de Maracaibo.'),
  ('roja', 'Comida', 'El pabellón criollo completo', 'La bandera nacional servida en un plato: caraotas, arroz, carne mechada y tajada. Patriotismo que se mastica.'),
  ('roja', 'Objetos', 'El termo de Avon', 'Herencia familiar más sagrada que la casa. Mantiene el café caliente desde 1987 y nadie sabe cómo, pero ay de quien lo bote.'),
  ('roja', 'Lugares', 'Sabana Grande', 'El bulevar donde puedes comprar un reloj ''Rolex'', un perro caliente y una predicción del futuro con la misma señora, todo en una sola cuadra.'),
  ('roja', 'Evento', 'La quincena que dura dos días', 'Cobras el 15, pagas todo el 16, y el 17 ya estás matando tigre otra vez. La quincena más corta del calendario gregoriano.'),
  ('roja', 'Dichos', '"Estar pelando bola"', 'No tener ni un centavo partido por la mitad. Estado financiero permanente del venezolano entre quincena y quincena.'),
  ('roja', 'Personajes', 'El guachimán del edificio', 'El verdadero dueño del condominio. Sabe a qué hora llegas, con quién y por qué, pero jura que «no vio nada».'),
  ('roja', 'Guachafitas', 'Tener tres canaimitas en la casa y ninguna prende', 'El cementerio de tablets del gobierno. Sirven de posavasos y de espejo para sacarse los pelos de la nariz.'),
  ('roja', 'Musica', 'Cardenales del Éxito', 'Que suenen a las 7 de la mañana en diciembre es ley no escrita de la abuela. Si no hay gaita prendida, es porque no hay luz.'),
  ('roja', 'Espanto', 'La Bola de Fuego', 'Una candela que rueda por la sabana de noche y que, según los abuelos, es un alma en pena. Según el municipio, es un transformador que volvió a explotar.'),
  ('roja', 'Personajes', 'Omar Vizquel', 'Sacaba outs con la mano pelada como si estuviera espantando un zancudo. El guante era pura decoración.'),
  ('roja', 'Comida', 'El asado negro de la abuela', 'Tan oscuro y tan sabroso que te hace dudar de tu fe en la cocina de tu mamá. Nadie sabe el secreto y nadie lo sabrá jamás.'),
  ('roja', 'Objetos', 'Las cholas', 'Calzado nacional multiusos: para la casa, para la bodega, para correr al carro y, en mano de tu mamá, arma teledirigida de precisión quirúrgica.'),
  ('roja', 'Lugares', 'El Metro de Caracas', 'Antes el orgullo de Latinoamérica; hoy una sauna rodante donde aprendes el olor de toda la ciudad sin pedirlo. ''Por favor, dejen salir antes de entrar'' (nadie obedece).'),
  ('roja', 'Evento', 'El sancocho familiar del domingo', 'Tres horas alrededor de un fogón, una tía revolviendo, un tío dando instrucciones que nadie pidió y un primo que solo aparece cuando ya está servido.'),
  ('roja', 'Dichos', '"Más sabe el diablo por viejo que por diablo"', 'La sabiduría de la abuela que te cachó la mentira antes de que terminaras de inventarla.'),
  ('roja', 'Personajes', 'El motorizado kamikaze', 'Cree que el espejo retrovisor es un adorno y la acera es un canal exclusivo. Te toca corneta hasta cuando vas caminando.'),
  ('roja', 'Guachafitas', 'Manejar con el brazo de afuera para que no se note que no hay aire', 'El ventilador de tracción humana. A 60 km/h refresca; en la cola te asas como tequeño olvidado.'),
  ('roja', 'Musica', 'El joropo recio', 'Cuatro, arpa, maracas y un señor zapateando con tanta fuerza que el piso pide clemencia. El llano entero en tres minutos de adrenalina.'),
  ('roja', 'Espanto', 'El Hachador del Monte', 'Lo oyes tumbando un árbol toda la noche, pero al amanecer no hay ni una rama caída. El único leñador que trabaja más que tú y produce menos.'),
  ('roja', 'Personajes', 'Pablo Sandoval', '''Kung Fu Panda'': demostró que se puede ganar la Serie Mundial con una barriga que entra primero al estadio que el resto del cuerpo.'),
  ('roja', 'Comida', 'Una cachapa con queso de mano y cochino frito', 'El maíz dulce, el queso que se estira y la grasa que perdona todo. Después necesitas una siesta de tres horas.'),
  ('roja', 'Objetos', 'El budare', 'Disco de hierro que pesa más que un muerto y sobrevive a tres generaciones, tres mudanzas y un divorcio. Las arepas saben a abuela.'),
  ('roja', 'Lugares', 'El Teleférico de Caracas', 'Subes al Ávila en una cajita de metal colgada de un cable y rezas dos veces: una al subir y otra cuando ves los precios de la cima.'),
  ('roja', 'Evento', 'El velorio con cerveza y dominó', 'Despedimos al difunto con respeto: capicúa, hielo, y la promesa de que «él hubiese querido que la pasáramos bien».'),
  ('roja', 'Dichos', '"Camarón que se duerme se lo lleva la corriente"', 'Si te descuidas un segundo en este país, te quitaron el puesto, el cambio y hasta la novia.'),
  ('roja', 'Personajes', 'La suegra que llega sin avisar', 'Aparece con una olla, una opinión sobre tu cocina y una maleta «por si acaso me quedo».'),
  ('roja', 'Guachafitas', 'Echarle agua de la batería al refresco para que rinda', 'Mentira, no le eches eso. Pero el primo sí lo hizo una vez y todavía lo recuerdan en los cumpleaños.'),
  ('roja', 'Musica', 'Despecho llanero a todo pulmón', 'Cuando el arpa llora más que tú, ya no sabes si estás triste o solo estás disfrutando el dolor con una cerveza en la mano.'),
  ('roja', 'Espanto', 'El Descabezado', 'Un espanto que anda buscando su cabeza por el camino. Tranquilo, no es el único en Venezuela que perdió la cabeza en este país.'),
  ('roja', 'Personajes', 'David Concepción', 'El campocorto de la Gran Maquinaria Roja que inventó el tiro de rebote en la grama artificial. Ingeniería criolla pura.'),
  ('roja', 'Comida', 'La arepa rellena de reina pepiada', 'Pollo, aguacate y mayonesa metidos en un puño de maíz. La reina de las arepas y nadie la destrona.'),
  ('roja', 'Objetos', 'La batea de lavar', 'El gimnasio gratuito de la abuela. Brazos de acero forjados a punta de jabón azul y sábanas mojadas.'),
  ('roja', 'Lugares', 'La Isla de Margarita', 'El plan B de todo venezolano que dice ''me voy a relajar''. Llegas con maletas vacías y vuelves con tres cavas, dos hamacas y cero plata.'),
  ('roja', 'Evento', 'La graduación con la promoción entera', 'Cuarenta familias, un mismo cotillón, y un acto que empieza dos horas tarde porque falta el padrino.'),
  ('roja', 'Dichos', '"Echar un camión"', 'Mentir con tal magnitud y desparpajo que merecerías un premio en lugar de un regaño.'),
  ('roja', 'Personajes', 'El fiebrúo del gym', 'Postea las pesas pero nunca la dieta. Tiene más fotos en el espejo del gimnasio que en su propia casa.'),
  ('roja', 'Guachafitas', 'El tío que llega a la fiesta y de una vez se mete en la cocina a opinar', 'El interventor de la parrilla. No trajo ni el carbón, pero sabe exactamente cuándo voltear la carne mejor que el dueño de la casa.'),
  ('roja', 'Musica', 'El cuatro desafinado de la fiesta', 'Siempre hay un primo que lo agarra, lo rasguea horrible y aun así nadie tiene el corazón de quitárselo.'),
  ('roja', 'Espanto', 'La Dientona', 'Una mujer hermosa hasta que sonríe y te enseña una dentadura que parece reja de panadería. La razón científica por la que no debes piropear en la oscuridad.'),
  ('roja', 'Personajes', 'José Altuve', 'Mide metro y medio pero batea más alto que el dólar paralelo. El más grande de los chiquitos.'),
  ('roja', 'Comida', 'Los tequeños de la fiesta', 'El único alimento que desaparece de la bandeja antes de que llegue la mitad de los invitados. Sin tequeños no hay fiesta venezolana.'),
  ('roja', 'Objetos', 'El Daewoo Tico', 'Una lata de sardinas con cuatro ruedas que, contra toda ley de la física, carga a siete personas, dos bombonas y un perro hasta la playa.'),
  ('roja', 'Lugares', 'Los Roques', 'El paraíso donde el agua es turquesa, la arena es blanca y la cuenta final es del color de un infarto.'),
  ('roja', 'Evento', 'El matriarcado decidiendo el menú navideño', 'Un consejo de abuelas, tías y la mamá que tiene la última palabra. Tú solo ralla el queso y cállate.'),
  ('roja', 'Dichos', '"Agarrar a alguien fuera de base"', 'Pillar a la persona desprevenida, como out en el béisbol pero en la vida real y sin posibilidad de reclamo.'),
  ('roja', 'Personajes', 'El chamo que pide la cola', 'Te jura que es «aquí cerquita» y te termina mandando a tres municipios de distancia.'),
  ('roja', 'Guachafitas', 'Guardar las bolsas plásticas dentro de otra bolsa plástica', 'La caja fuerte de toda abuela venezolana. Ahí también hay botones sueltos, llaves de candados que ya no existen y un real partío.'),
  ('roja', 'Musica', 'Las parrandas decembrinas del barrio', 'Un grupo de señores con furruco y tambora que aparecen sin avisar en tu casa a las 11 p.m. y se van con hallaca y ron en el cuerpo.'),
  ('roja', 'Espanto', 'El Cucú', 'El terror número uno de los muchachitos que no quieren dormir. Nadie sabe cómo es, pero todos saben que viene si no te tomas la sopa.'),
  ('roja', 'Personajes', 'Salvador Pérez', 'Catcher gigante que abraza al pícher después de cada juego como si fuera su última empanada antes de la cola.'),
  ('roja', 'Comida', 'El cachito de jamón recién horneado', 'La razón por la que un venezolano se levanta temprano un domingo. Caliente, esponjoso y con el jamón asomándose por la punta.'),
  ('roja', 'Objetos', 'El Malibú del 78', 'Un tanque de guerra con tapicería de peluche. Gasta más gasolina que un avión pero nunca, jamás, te deja botado.'),
  ('roja', 'Lugares', 'Mérida', 'La ciudad de la eterna neblina, los estudiantes y la única calor que se quita con una cobija. Aquí el frío sí existe, aunque en Maracaibo no lo crean.'),
  ('roja', 'Evento', 'Montar la gaita desde octubre', 'Mientras el resto del mundo apenas piensa en Halloween, aquí ya suena el furro y huele a hallaca.'),
  ('roja', 'Dichos', '"Hacerse la vista gorda"', 'Mirar para otro lado profesionalmente, especialmente cuando el problema requiere que tú hagas algo.'),
  ('roja', 'Personajes', 'La doña de la junta de condominio', 'Convoca asamblea por una bombilla fundida y lleva minuta de quién no pagó la cuota desde 2014.'),
  ('roja', 'Guachafitas', 'Llamar a alguien por el nombre completo cuando ya estás molesto', 'El misil teledirigido materno. Cuando suena tu segundo nombre, ya sabes que la cosa pasó de castaño a oscuro.'),
  ('roja', 'Musica', 'Radio Rochela', 'Donde aprendimos que cualquier desgracia nacional se sobrevive mejor si primero te ríes de ella un viernes por la noche.'),
  ('roja', 'Espanto', 'El Coco', 'El gerente de cobranzas del mundo infantil: «Duérmete niño, duérmete ya, que viene el Coco y te comerá». Negociación de horario de sueño con amenaza incluida.'),
  ('roja', 'Personajes', 'Edgardo Alfonzo', 'El cangrejo del Cúcuta natal que defendió la segunda base en Nueva York mejor que tú defiendes tus excusas.'),
  ('roja', 'Comida', 'El pan canilla calientico', 'Sale de la panadería y no llega entero a la casa. Siempre falta la punta porque alguien ''la probó'' en el camino.'),
  ('roja', 'Objetos', 'El Caprice clásico', 'El carro del tío que ''lo va a restaurar algún día''. Lleva 15 años en el estacionamiento con una sábana encima y media pieza menos.'),
  ('roja', 'Lugares', 'El Teleférico de Mérida', 'El más alto y largo del mundo, donde subes al Pico Espejo a buscar nieve y bajas con soroche, los labios morados y una foto borrosa.'),
  ('roja', 'Evento', 'El viacrucis para conseguir efectivo', 'Cuatro cajeros, tres bancos, una cola eterna y al final te dan el límite diario que no alcanza ni para el pasaje.'),
  ('roja', 'Dichos', '"Estar como anillo al dedo"', 'Que algo te queda tan perfecto que parece que el universo lo fabricó pensando solo en ti.'),
  ('roja', 'Personajes', 'El que se cuela en la fila del banco', 'Llega «buscando a un amigo que ya estaba» y de repente está adelante de todos con cara de inocente.'),
  ('roja', 'Guachafitas', 'Ponerle nombre al carro como si fuera familia', '«La Catira» tiene 23 años, dos puertas que no abren y un motor que reza el rosario en cada subida, pero es de la casa.'),
  ('roja', 'Musica', 'Sábado Sensacional', 'Cinco horas de televisión donde cabía un cantante, un concurso, una telenovela en cápsula y la promesa de un carro 0 km que nadie de tu familia ganó jamás.'),
  ('roja', 'Espanto', 'Las brujas de Catia', 'Vuelan en escoba sobre los cerros y, dicen, se transforman en lechuza. Las únicas que consiguen estacionamiento en Catia un viernes en la noche.'),
  ('roja', 'Personajes', 'Antonio Armas', 'Líder jonronero de la Liga Americana cuando los venezolanos todavía pensábamos que el béisbol era nuestro destino manifiesto.'),
  ('roja', 'Comida', 'Los golfeados con queso y melao', 'Dulces, pegajosos y con anís. Un infarto envuelto en papas, pero qué rico se va uno.'),
  ('roja', 'Objetos', 'La moto de bachaquear', 'Vehículo de carga olímpico: cabe la familia, el mercado completo y una nevera amarrada con mecate. Casco opcional, fe obligatoria.'),
  ('roja', 'Lugares', 'El Salto Ángel', 'La cascada más alta del planeta, que para verla tienes que volar en una avioneta, navegar un río y caminar tres horas. Vale cada gota.'),
  ('roja', 'Evento', 'La cola del banco que no avanza', 'Entraste joven, saliste con barba. El de adelante lleva un mes y ya hizo amigos.'),
  ('roja', 'Dichos', '"Ir a pie de bola"', 'Lanzarse a una situación sin plan, sin presupuesto y sin la menor idea, pero con toda la actitud.'),
  ('roja', 'Personajes', 'El tío que arma el sancocho', 'El general de cinco estrellas del fogón. No deja que nadie toque la olla, pero sí que todos laven los platos.'),
  ('roja', 'Guachafitas', 'El que se pone los lentes oscuros adentro del bautizo', 'Llegó del pre-despacho del sábado directo a la iglesia. Cree que nadie nota que está rezando con resaca.'),
  ('roja', 'Musica', 'Súper Sábado Sensacional', 'Porque a un programa de cinco horas en Venezuela siempre se le puede agregar la palabra «Súper» y media hora más.'),
  ('roja', 'Espanto', 'El culto a María Lionza en Sorte', 'Subes la montaña con tabaco, ron y velas, y bajas con la espalda derecha y el alma limpia. Spa espiritual venezolano, todo incluido, menos el seguro.'),
  ('roja', 'Personajes', 'Ozzie Guillén', 'El primer mánager latino en ganar una Serie Mundial. Dice más groserías por minuto que un motorizado en hora pico.'),
  ('roja', 'Comida', 'Las mandocas zulianas', 'Maíz, papelón y queso fritos en forma de herradura. Maracaibo en cada mordisco, con su calor incluido.'),
  ('roja', 'Objetos', 'El billete de un millón de bolívares', 'Pieza de museo que un día compraba una casa y al mes siguiente no alcanzaba para un chicle. Ahora sirve para tapar la gotera.'),
  ('roja', 'Lugares', 'Coro y sus médanos', 'El único lugar de Venezuela donde te metes arena hasta en el alma y juras que estás en el Sahara, pero con cocada al lado.'),
  ('roja', 'Evento', 'El «ya casi llego» que son dos horas', 'La unidad de tiempo más elástica del idioma venezolano. Equivale a «ni he salido».'),
  ('roja', 'Dichos', '"Dejar a alguien plantado"', 'Acordar verse a las 3 y aparecerte nunca, dejando al otro echando raíces en la esquina.'),
  ('roja', 'Personajes', 'El vivo que se monta en la cola ajena', 'Especialista en aparecer cuando ya casi llega el turno. Tiene PhD en «yo estaba aquí desde temprano».'),
  ('roja', 'Guachafitas', 'Tapar el hueco del techo con una tobo y una ponchera', 'La ingeniería hidráulica criolla. Cuando llueve fuerte suena como batería de salsa y hay que vaciar a las 3 a.m.'),
  ('roja', 'Musica', 'Bienvenidos', 'El programa de humor donde un personaje en franela se volvía más memorable que cualquier discurso presidencial de la época.'),
  ('roja', 'Espanto', 'El Negro Felipe', 'El bravo de la Corte de María Lionza, puro tabaco y respeto. Cuando él se monta en el material, hasta el más malandro se persigna.'),
  ('roja', 'Personajes', 'Francisco Rodríguez ''K-Rod''', 'Cerraba juegos con tanto drama que el corazón del fanático cerraba antes que el inning.'),
  ('roja', 'Comida', 'Los bollitos pelones con guiso', 'Bolitas de maíz nadando en salsa de tomate. La merienda que tu abuela hacía con lo que sobraba y quedaba mejor que un restaurante.'),
  ('roja', 'Objetos', 'La cesta ticket', 'Aquel cuadernito de cupones que te hacía sentir rico el día de pago y pobre el día 16. El mercado entero olía a esperanza.'),
  ('roja', 'Lugares', 'Maracaibo a mediodía', 'No es un lugar, es una sentencia. El sol no calienta, te interroga. El asfalto se derrite y el aire acondicionado es un derecho humano.'),
  ('roja', 'Evento', 'El primero de enero con la casa llena de hallacas', 'Sobrevives a base de hallaca recalentada hasta el 6 de enero. La dieta arranca después de Reyes.'),
  ('roja', 'Dichos', '"Estar en la olla"', 'Tocar fondo total: sin trabajo, sin real y con la nevera haciendo eco.'),
  ('roja', 'Personajes', 'El gandolero de la autopista', 'Maneja un mastodonte de 18 ruedas como si fuera una bicicleta y se cambia de canal sin avisar a nadie.'),
  ('roja', 'Guachafitas', 'Comprar un solo cigarro y pedir el encendido prestado', 'El microemprendedor del vicio. Compra al detal, fuma a crédito y siempre anda «sin reales pero con ganas».'),
  ('roja', 'Musica', 'Cásate y Verás', 'El reality antes de que existieran los realities: parejas peleando en vivo para deleite de toda la familia desde el sofá.'),
  ('roja', 'Espanto', 'La Reina María Lionza', 'La diosa de la montaña, montada en su danta, reina indiscutida de Sorte. La única figura femenina que aparece en una autopista, en un billete y en un altar.'),
  ('roja', 'Personajes', 'Félix Hernández', '''El Rey Félix'' lanzó un juego perfecto y nosotros ni perfectos para llegar temprano al trabajo.'),
  ('roja', 'Comida', 'El hervido de gallina del domingo', 'El caldo que resucita a un muerto, cura la ratón y arregla cualquier problema existencial. Lleva auyama, ocumo y un secreto.'),
  ('roja', 'Objetos', 'El tobo de agua para cuando no hay', 'Reserva estratégica nacional almacenada en el baño. Sagrado e intocable, hasta que llegan visitas y se vacía en una tarde.'),
  ('roja', 'Lugares', 'El Puente sobre el Lago de Maracaibo', 'Ocho kilómetros de fe pura sobre el agua. Si te quedas pegado en el medio, ya eres del Zulia legalmente.'),
  ('roja', 'Evento', 'Cuadrar la vuelta del transporte público', 'Una negociación digna de Wall Street: «no tengo sencillo», «yo tampoco», y al final pagas de más por principio.'),
  ('roja', 'Dichos', '"No hay arroz que no se queme"', 'Hasta el más experto mete la pata; consuelo nacional para cuando arruinas algo importante.'),
  ('roja', 'Personajes', 'El pana que «te resuelve» todo', 'Conoce un primo que tiene un compadre que vende eso más barato. Nunca aparece, pero la fe nunca muere.'),
  ('roja', 'Guachafitas', 'El primo que «sabe» de carros y deja el tuyo peor', 'Le metió mano al ruidito y ahora suena a maracas. «Eso ya estaba así», jura con la cara de palo.'),
  ('roja', 'Musica', 'La gaita de protesta', 'El único género musical donde puedes felicitar a la Virgen y reclamarle al gobierno en la misma estrofa, sin perder el ritmo.'),
  ('roja', 'Espanto', 'El Tirano Aguirre', 'El conquistador loco que recorre la isla de Margarita convertido en candela errante. El primer venezolano que se peleó con todo el mundo y siguió dando vueltas sin rumbo.'),
  ('roja', 'Personajes', 'Magglio Ordóñez', 'Bateaba con un swing tan elegante que parecía que estaba firmando autógrafos en pleno turno al bate.'),
  ('roja', 'Comida', 'El sancocho de pescado a orillas del río', 'Hecho en fogón de leña con lo que cayó esa mañana. El olor a humo lo hace ilegalmente delicioso.'),
  ('roja', 'Objetos', 'La nevera ''ejecutiva'' de cervezas', 'La nevera vieja que se mudó al porche con un solo propósito en la vida: mantener las polares heladas para el comité de los domingos.'),
  ('roja', 'Lugares', 'Galipán', 'El pueblito de las flores y las fresas con crema arriba del Ávila, al que solo se llega en un jeep que sube por una carretera diseñada por el mismísimo diablo.'),
  ('roja', 'Evento', 'La parranda que llega a tu casa sin avisar', 'Tocan la puerta con cuatro, maracas y furruco. No hay forma de decir que no, ya están adentro pidiendo el ponche.'),
  ('roja', 'Dichos', '"Échale pichón"', 'Ponerle ganas y fuerza a la cosa aunque no sepas bien qué estás haciendo. La filosofía de toda bomba de agua manual.'),
  ('roja', 'Personajes', 'La señora que regatea hasta en el chino', 'Pelea un descuento por un paquete de espaguetis como si estuviera comprando una casa.'),
  ('roja', 'Guachafitas', 'Mandar al menor de la casa a comprar a la bodega de noche', 'El sacrificio ritual familiar. Va llorando, regresa corriendo y jura que vio al Silbón en la esquina.'),
  ('roja', 'Musica', 'Un merengue venezolano de los 90', 'Ritmo pegajoso, letra que no significaba nada y un paso de baile que tu tío todavía saca en cada matrimonio.'),
  ('roja', 'Espanto', 'El Dr. José Gregorio Hernández', 'El médico de los venezolanos, con su sombrero y su traje negro. Lo invocas para una operación complicada y para que te aparezca el repuesto del carro que no se consigue.'),
  ('roja', 'Personajes', 'Bobby Abreu', 'Esperaba la base por bolas con la paciencia de quien lleva tres horas en la cola del banco.'),
  ('roja', 'Comida', 'El chicharrón crujiente con casabe', 'Grasa, sal y un crujido que se escucha en la casa del vecino. La presión arterial es un problema del Yo del futuro.'),
  ('roja', 'Objetos', 'El ventilador ''recargable'' chino', 'Promete ocho horas de brisa y dura veinte minutos. Cuando se va la luz, hace un ruido de licuadora y luego, traición.'),
  ('roja', 'Lugares', 'Chacao', 'El municipio donde todo cuesta el doble, todos andan apurados y hasta el vigilante del edificio tiene mejor cuerpo que tú.'),
  ('roja', 'Evento', 'El reencuentro de la familia en diciembre', 'Aparecen primos que no veías desde la infancia y un tío que regresó «del exterior» a contarte lo bien que le va.'),
  ('roja', 'Dichos', '"Buscarle la quinta pata al gato"', 'Complicar un problema sencillo hasta volverlo irresoluble, deporte favorito de toda reunión de condominio.'),
  ('roja', 'Personajes', 'El cobrador del autobús', 'Equilibrista que cuelga de la puerta gritando la ruta completa de un solo respiro mientras te da el vuelto exacto.'),
  ('roja', 'Guachafitas', 'Calentar la comida de ayer y jurar que sabe mejor recalentada', 'El sommelier del refrigerador. «El pabellón del segundo día tiene cuerpo», dice mientras esconde que no hay para más nada.'),
  ('roja', 'Musica', 'El Trabuco salsero en el equipo de sonido', 'Suena un par de trompetas y de repente todos en la fiesta se creen soneros, aunque ninguno sepa de dónde sacar el coro.'),
  ('roja', 'Espanto', 'El Espanto de la Quebrada', 'Esa sombra que cruza el agua cuando vas pasando solo de noche. Puede ser un alma en pena o puede ser el vecino robando los aguacates del cerro.'),
  ('roja', 'Personajes', 'Carlos Hernández', 'Boxeador campeón mundial que repartía golpes como mamá repartiendo correazos: precisos y sin avisar.'),
  ('roja', 'Comida', 'Una malta bien fría', 'La bebida que tu mamá te daba ''porque tiene hierro''. Dulce, espesa y con esa espuma que pide acompañar con queso amarillo.'),
  ('roja', 'Objetos', 'El celular con la pantalla rota', 'Una telaraña de vidrio que igual contesta, igual postea y igual te cortas el dedo cada vez que respondes un mensaje.'),
  ('roja', 'Lugares', 'Petare', 'El barrio más grande de Latinoamérica, una montaña de bloques rojos que de día es laberinto y de noche es leyenda. Respeto absoluto.'),
  ('roja', 'Evento', 'Estrenar ropa el 31 de diciembre', 'Tradición sagrada: si no estrenas, el año entra arrugado. Y la interior amarilla es obligatoria.'),
  ('roja', 'Dichos', '"Quedarse con los crespos hechos"', 'Prepararte con todo el entusiasmo para algo que al final no pasó. La decepción más arreglada del país.'),
  ('roja', 'Personajes', 'El profesor que cae mal a todo el salón', 'Pone examen sorpresa el lunes y jura que «esto lo van a usar toda la vida». Spoiler: no.'),
  ('roja', 'Guachafitas', 'El que pide «un toquecito» de la cerveza ajena y se la baja completa', 'El robo a mano armada más educado de Venezuela. Te devuelve la lata vacía con una sonrisa de gratitud.'),
  ('roja', 'Musica', 'Salsa de la dura, de la que no se baila pegado', 'Esa que el melómano del grupo te pone para «educarte» mientras tú solo querías algo para mover el esqueleto.'),
  ('roja', 'Espanto', 'El Carretón de la Muerte', 'Una carreta tirada por bueyes que pasa rechinando a medianoche cargada de almas. El único transporte público que sí cumple horario en este país.'),
  ('roja', 'Personajes', 'Edwin Valero', 'Invicto con nocaut en todas sus peleas. Tenía un tatuaje de Chávez en el pecho y un gancho que mandaba a dormir.'),
  ('roja', 'Comida', 'El papelón con limón en una jarra de un litro', 'La gatorade criolla. Si trabajaste bajo el sol, esto te devuelve el alma al cuerpo en dos tragos.'),
  ('roja', 'Objetos', 'Las pastillas de Atamel', 'El paracetamol nacional que cura desde la fiebre hasta el mal de amores. Si no te lo baja el Atamel, ya eso es brujería.'),
  ('roja', 'Lugares', 'El bulevar de Catia', 'Universidad de la calle donde se vende, se grita, se regatea y se sobrevive. Si encuentras lo que buscas a buen precio, eres un genio del comercio.'),
  ('roja', 'Evento', 'Las doce uvas a la medianoche', 'Te atragantas con doce uvas mientras pides doce deseos y alguien grita «¡salud!» con sidra tibia.'),
  ('roja', 'Dichos', '"Echar broma"', 'Molestar, fastidiar o joder a alguien con cariño, hasta que ya no es tan con cariño.'),
  ('roja', 'Personajes', 'El reguetonero del barrio', 'Sueña con el Hard Rock pero por ahora graba en el cuarto con una cobija pegada a la pared.'),
  ('roja', 'Guachafitas', 'Estacionar en doble fila y dejar las luces intermitentes como pidiendo perdón', 'Las cuatro luces son el «ya vengo» universal. Significa cualquier cosa entre dos minutos y dos horas.'),
  ('roja', 'Musica', 'La hora del vallenato en la barra', 'Cuando ya nadie está sobrio y todos cantan «la nevera» como si la letra fuera la historia de su propia vida.'),
  ('roja', 'Espanto', 'La Mula Maniá', 'Una mujer condenada a vagar convertida en mula encadenada por meterse con un cura. La moraleja del pueblo: cuidado con quién te enamoras, que terminas relinchando.'),
  ('roja', 'Personajes', 'Antonio Cermeño', 'Doble campeón mundial de boxeo que pegaba más duro que la inflación de un solo día.'),
  ('roja', 'Comida', 'La chicha del señor de la esquina', 'Espesa, con canela por encima y servida en vaso plástico. Te la tomas sin preguntar de qué año es el arroz.'),
  ('roja', 'Objetos', 'El frasco de Vick VapoRub', 'Medicina universal venezolana: tos, gripe, dolor de cabeza, picadura de zancudo y, según tu abuela, hasta para los nervios. Úntalo y reza.'),
  ('roja', 'Lugares', 'La playa de Choroní', 'Carretera de mil curvas que te marea hasta el alma, pero al final hay un mar bravo, unos tambores y un cocofrío que te perdona todo.'),
  ('roja', 'Evento', 'Correr con la maleta vacía dando la vuelta a la manzana', 'El ritual del Año Nuevo para que el próximo traiga viajes. El vecino te ve y ya sabe lo que viene.'),
  ('roja', 'Dichos', '"Tirar la toalla"', 'Rendirse de manera oficial y solemne, generalmente tres minutos antes de que la cosa iba a funcionar.'),
  ('roja', 'Personajes', 'La vecina que lo sabe todo', 'Sistema de inteligencia más eficiente que el SEBIN. Sabe que terminaste con tu novia antes que tú.'),
  ('roja', 'Guachafitas', 'Bautizar como «el chinito» a cualquier abasto sin importar el dueño', 'Geografía nacional: todo barrio tiene su chinito, su tasca y una esquina donde «mataron a uno una vez».'),
  ('roja', 'Musica', 'Tambor barloventeño en Semana Santa', 'Tres tambores, un coro de tías y la garantía de que para el lunes nadie en San Francisco de Yare se podrá levantar de la cama.'),
  ('roja', 'Espanto', 'El Familiar de la hacienda', 'Una bestia que el dueño alimentaba con peones para que el negocio prosperara. El primer caso documentado de explotación laboral con monstruo incluido.'),
  ('roja', 'Personajes', 'Jorge Linares', 'El barquisimetano que conquistó tres categorías. Pegaba tan rápido que el rival se enteraba por las redes sociales.'),
  ('roja', 'Comida', 'El guarapo de papelón en el campo', 'Azúcar en estado puro disfrazada de bebida natural. El combustible oficial de cualquier trabajador venezolano.'),
  ('roja', 'Objetos', 'La pava (la gorra)', 'Accesorio sagrado del beisbolero, del taxista y del que no se peinó. Mientras más sucia y desteñida, más respeto impone.'),
  ('roja', 'Lugares', 'El Parque del Este', 'El oasis verde de Caracas, donde la gente trota, los niños ven el avión de Tito y siempre hay un señor haciendo Tai Chi a las seis de la mañana.'),
  ('roja', 'Evento', 'El partido de la Vinotinto que para al país', 'Oficinas vacías, calles muertas y un país entero rezándole al VAR.'),
  ('roja', 'Dichos', '"Estar más arrecho que tigre flaco"', 'Nivel de molestia tan elevado que hasta los animales del zoológico se enteran.'),
  ('roja', 'Personajes', 'El que cuadra el carro mal estacionado', 'Deja el carro atravesado y se va tranquilo, con el número de teléfono detrás del vidrio para que «lo llames».'),
  ('roja', 'Guachafitas', 'El que graba el concierto entero por el teléfono y nunca lo vuelve a ver', 'El camarógrafo frustrado. Pagó la entrada para ver el show por una pantallita de seis pulgadas tapándole la vista al de atrás.'),
  ('roja', 'Musica', 'El calipso de El Callao en Carnaval', 'Madamas, medio pintos y mineros bailando: la única semana del año en que Bolívar entero se olvida del oro por el ritmo.'),
  ('roja', 'Espanto', 'La Llorona del Guárico', 'Versión sabanera de la madre que perdió a sus hijos en el río. Llora con tan buen oído que hasta los arpistos de la zona le tienen envidia.'),
  ('roja', 'Personajes', 'Leslie Pappoe... digo, Tomás Rincón', '''El General'' de la Vinotinto, que corre toda la cancha como si lo persiguiera la PTJ.'),
  ('roja', 'Comida', 'Un ron añejo con hielo y nada más', 'El orgullo nacional embotellado. Quien le echa refresco comete un crimen castigado por la sociedad.'),
  ('roja', 'Objetos', 'El carrito por puesto', 'Transporte público y montaña rusa a la vez. Caben cuatro atrás aunque el carro sea para tres, y el chofer maneja como si lo persiguieran.'),
  ('roja', 'Lugares', 'Plaza Venezuela', 'El corazón vial de Caracas: una fuente bonita rodeada de la mayor concentración de bocinas y groserías por metro cuadrado del país.'),
  ('roja', 'Evento', 'La caída del sistema en el banco', '«Está caído el sistema» — la frase que justifica todo desde 1998. No hay fecha de regreso.'),
  ('roja', 'Dichos', '"Echarse fresco"', 'Relajarse y no preocuparse por nada, idealmente con un aire acondicionado robado al vecino.'),
  ('roja', 'Personajes', 'El político en campaña', 'Solo aparece cada cinco años, te regala una gorra y te promete asfaltar la calle que lleva diez gobiernos rota.'),
  ('roja', 'Guachafitas', 'Hacerle la cruz a la comida del difunto antes de comérsela', 'Respeto y hambre en partes iguales. Primero se reza, después se devora el guiso del velorio sin remordimiento.'),
  ('roja', 'Musica', 'El aguinaldo que canta el coro del colegio', 'Veinte niños desafinados, una pandereta y un maestro rezando para que el acto de fin de año termine antes del apagón.'),
  ('roja', 'Espanto', 'El Ánima de Pica-Pica', 'El alma milagrosa de un bandolero que ahora hace favores desde el más allá. Le pides un milagro y te lo cumple, pero con la condición de que no preguntes cómo.'),
  ('roja', 'Personajes', 'Juan ''El Toro'' Arango... no, Rolando Fonseca... mejor: Giancarlo Maldonado', 'Goleador de la Vinotinto en la época en que un gol nuestro era noticia internacional de tres días.'),
  ('roja', 'Comida', 'Una cerveza bien fría en la playa', 'Tiene que estar tan helada que duela la mano. Si está ''al tiempo'' es motivo de pelea familiar.'),
  ('roja', 'Objetos', 'La olla arrocera con tapa amarrada', 'El cierre se rompió en 2009 y desde entonces vive amarrada con un mecate o una liga. Sigue haciendo el arroz perfecto, eso sí.'),
  ('roja', 'Lugares', 'La autopista Regional del Centro', 'Donde los caraqueños van a llorar los domingos en la noche. Tres horas para avanzar dos kilómetros y un alcabala que aparece de la nada.'),
  ('roja', 'Evento', 'El bautizo que se vuelve fiesta hasta las 3 a.m.', 'Empezó con una misa y terminó con salsa, whisky y el padrino bailando encima de una silla.'),
  ('roja', 'Dichos', '"Comerse un cable"', 'Pasar hambre extrema o aguantar necesidad por falta de real. Plato principal del mes de enero.'),
  ('roja', 'Personajes', 'El que llega tarde a todo', 'Confirmó que «ya casi llega» hace dos horas. Maneja con la hora venezolana, que no aparece en ningún reloj del mundo.'),
  ('roja', 'Guachafitas', 'Pintar el frente de la casa y dejar los lados con el bloque pelado', 'La fachada presidencial. Por delante es Beverly Hills, por detrás es obra negra desde el gobierno de Caldera.'),
  ('roja', 'Musica', 'El reguetón sonando en la buseta a las 6 a.m.', 'Porque el chofer decidió que tu derecho a despertarte en silencio es secundario frente a su derecho a perreo matutino.'),
  ('roja', 'Espanto', 'El Ánima Sola', 'El alma a la que nadie le reza y por eso te ayuda a cambio de una velita. La definición espiritual de «yo te resuelvo, pero acuérdate de mí».'),
  ('roja', 'Personajes', 'José Manuel Rey', 'El capitán defensor de la Vinotinto. Marcaba al delantero rival más pegado que un familiar pidiendo prestado.'),
  ('roja', 'Comida', 'El batido de parchita con leche', 'Agridulce y traicionero: rico al primer trago, pero te deja la boca como lija. Aun así te tomas dos.'),
  ('roja', 'Objetos', 'La cocina de kerosén de la abuela', 'Reliquia que aún espera en el depósito por el día que ''no haya gas''. Huele a infancia y a peligro de explosión.'),
  ('roja', 'Lugares', 'El Cementerio (la zona)', 'Un barrio de Caracas con nombre de chiste fácil, pero terminal de buses, comercio y movimiento las 24 horas. Vivito y coleando, irónicamente.'),
  ('roja', 'Evento', 'La playa en Semana Santa con medio país encima', 'Llegas a las 6 a.m. y aún no consigues puesto. La toalla del vecino está pegada a la tuya.'),
  ('roja', 'Dichos', '"Estar pendiente del medio"', 'Vivir vigilando lo que hace todo el mundo menos tú mismo. Talento natural de toda tía con WhatsApp.'),
  ('roja', 'Personajes', 'El amigo que nunca tiene efectivo', 'Siempre olvida la billetera justo cuando llega la cuenta y promete una transferencia que nunca cae.'),
  ('roja', 'Guachafitas', 'El que se aprende el baile de TikTok pero solo lo hace en bodas', 'Practicó dos meses encerrado en el cuarto para soltar el pasito a las 11 p.m. cuando ya todos están prendidos.'),
  ('roja', 'Musica', 'La Billo''s Caracas Boys', 'La banda que tu abuelo jura que sonaba mejor que cualquier cosa de hoy, y honestamente, en eso no le falla la memoria.'),
  ('roja', 'Espanto', 'El Hombre Caimán', 'Un pescador que por espiar a las mujeres bañándose quedó mitad hombre, mitad caimán. La advertencia ancestral contra el sapo de río.'),
  ('roja', 'Personajes', 'Gabriel Cichero', 'Defensor de la Vinotinto con cara de pana que te fía hasta la quincena que nunca llega.'),
  ('roja', 'Comida', 'El marrón claro de la panadería', 'El café que pides cuando no sabes pedir café. Ni muy negro ni muy con leche: el venezolano del término medio.'),
  ('roja', 'Objetos', 'El abanico de cartón de la funeraria', 'Publicidad de servicios fúnebres convertida en herramienta de supervivencia en misa, en velorio y en el calor de las 2 p.m.'),
  ('roja', 'Lugares', 'La cola del banco', 'El deporte nacional sin medallas. Llegas a las siete de la mañana, sales a la una de la tarde y resulta que el sistema ''estaba caído''.'),
  ('roja', 'Evento', 'El asado negro de la abuela los domingos', 'Una receta que nadie ha logrado replicar porque ella «le echa amor» y nunca te dice las cantidades.'),
  ('roja', 'Dichos', '"Pasar más hambre que maestro de escuela"', 'Nivel de pobreza tan reconocido que hasta tiene profesión asignada.'),
  ('roja', 'Personajes', 'La tía que pellizca los cachetes', 'Te ve y grita «¡pero qué grande está!» mientras te arranca media cara de un solo apretón.'),
  ('roja', 'Guachafitas', 'Echarle limón a todo, hasta a las cosas que no llevan limón', 'El que le exprime limón a la pizza, a los tequeños y casi al café. «Es que así mata el bicho», explica sin pruebas.'),
  ('roja', 'Musica', 'La Dimensión Latina con su trombón', 'El sonido que convirtió una fiesta de barrio caraqueño en orquesta sinfónica de la salsa, sin pedir permiso a nadie.'),
  ('roja', 'Espanto', 'La Cigua', 'Una mujer salvaje del monte con los pies al revés para que no sepas hacia dónde se fue. La única que enreda más que un GPS sin señal en El Ávila.'),
  ('roja', 'Personajes', 'Rafael Dudamel', 'Arquero histórico y luego DT de la Vinotinto. Atajaba penales y críticas con la misma serenidad.'),
  ('roja', 'Comida', 'La cocada del playero', 'Coco, hielo y leche condensada gritada a todo pulmón bajo el sol. ''¡Cocada, cocadaaa!'' es el himno de la playa.'),
  ('roja', 'Objetos', 'El control remoto con teipe', 'Forrado en cinta para que no se le salgan las pilas. Hay que apretarlo con fe y apuntarlo en ángulo exacto para que cambie el canal.'),
  ('roja', 'Lugares', 'La panadería de la esquina', 'El templo del cafecito, el cachito y el chisme del barrio. Donde ''me das un palito'' significa pan, y el cafecito viene con noticia gratis.'),
  ('roja', 'Evento', 'El cumpleaños con torta de tres leches sudada', 'Sale del refrigerador transpirando azúcar. Igual te comes dos pedazos y pides para llevar.'),
  ('roja', 'Dichos', '"Echar el resto"', 'Darlo absolutamente todo en algo, sin guardar nada para mañana, como si no hubiera otra quincena.'),
  ('roja', 'Personajes', 'El que pone la música a todo volumen en la madrugada', 'Pretende que toda la cuadra disfrute su playlist de salsa brava a las 3:00 a.m., quiéranlo o no.'),
  ('roja', 'Guachafitas', 'Comprar la torta «para la dieta» y comérsela parado frente a la nevera', 'Las calorías comidas de pie y a escondidas no cuentan. Es ciencia, lo dijo la prima que estudió un semestre de nutrición.'),
  ('roja', 'Musica', 'Un changa tuki sonando en el malandreo', 'El género más venezolano y más subestimado: nació en las discotecas de barrio y el mundo entero lo copió sin dar las gracias.'),
  ('roja', 'Espanto', 'El Pájaro del Mal Agüero', 'Si canta cerca de tu casa, algo malo va a pasar; si no canta, igual algo malo va a pasar, esto es Venezuela. Periodista de aves, siempre con la noticia mala.'),
  ('roja', 'Personajes', 'Salomón Rondón... no: Josef Martínez', 'Goleador récord de la MLS que celebraba con un rugido más fuerte que el de tu estómago en ayuno intermitente forzado.'),
  ('roja', 'Comida', 'La jalea de mango verde', 'Ácida, oscura y vendida en bloques sospechosos. Te hace doler la barriga pero igual le pides al señor ''una más''.'),
  ('roja', 'Objetos', 'El colador de media de café', 'Esa bolsita renegrida que nadie limpia bien pero hace el guayoyo más sabroso del planeta. Cuestión de paladar, no de higiene.'),
  ('roja', 'Lugares', 'El abasto del chino', 'Abre a las cinco de la mañana, cierra a medianoche y tiene de todo. ''No hay sencillo, jefe'' es la frase más repetida del establecimiento.'),
  ('roja', 'Evento', 'El parao de pelea de gallos en el pueblo', 'Apuestas, gritos, polvo y un domingo entero que se va sin que te des cuenta.'),
  ('roja', 'Dichos', '"Hablar paja"', 'Decir mucho y no decir nada. Especialidad de político en campaña y de pana después del tercer trago.'),
  ('roja', 'Personajes', 'El cuñado opinador', 'Experto en economía, fútbol, política y tu vida personal. Nadie sabe en qué trabaja, pero todo lo critica.'),
  ('roja', 'Guachafitas', 'El que llega tarde y de una se sirve como si hubiera ayudado a cocinar', 'El director técnico del sancocho. No picó ni una papa, pero es el primero en agarrar el plato más hondo.'),
  ('roja', 'Musica', 'Kiara y Ricardo Montaner cantando «Vivir lo nuestro»', 'El dueto que hizo llorar a una generación entera de quinceañeras y que todavía suena en cada radio romántica que se respete.'),
  ('roja', 'Espanto', 'Juan Machete', 'El llanero que vendió el alma al diablo por ganado y terminó vagando por la sabana sin un solo becerro. El primer venezolano arruinado por confiar en un negocio que sonaba muy bueno.'),
  ('roja', 'Personajes', 'Yeferson Soteldo', 'Chiquitico y habilidoso, gambeteaba rivales como tú esquivas a los que venden rifas en el semáforo.'),
  ('roja', 'Comida', 'El dulce de lechosa con clavitos', 'El postre obligatorio de diciembre que nadie pide pero todos comen. Dulce, fibroso y con olor a Navidad.'),
  ('roja', 'Objetos', 'La perinola de palo', 'Juguete y arma de tradición. Tu tío todavía la juega en Navidad con una concentración digna de un cirujano.'),
  ('roja', 'Lugares', 'El mercado municipal', 'Donde el verdulero te grita ''a la orden mi amor'' aunque tengas 80 años, y la auyama siempre viene ''sin pesar el pedacito de ñapa''.'),
  ('roja', 'Evento', 'El paseo a Margarita pagado a plazos', 'El viaje soñado que llevas pagando dos años y todavía no has hecho la maleta.'),
  ('roja', 'Dichos', '"Caerle a alguien a punta de bolígrafo"', 'Quejarse o atacar a alguien por escrito en el grupo, porque cara a cara no hay tanto valor.'),
  ('roja', 'Personajes', 'El vendedor de empanadas de la playa', 'Camina kilómetros bajo el sol cargando la cesta y te las vende calientes aunque tú estés sudando frío.'),
  ('roja', 'Guachafitas', 'Guardar el bombillo bueno y dejar prendido el malo «por si acaso»', 'La administración de recursos del venezolano: lo bueno se guarda para nunca, lo malo se usa hasta que explote.'),
  ('roja', 'Musica', 'La novela de las 9 que paralizaba el país', 'Antes de Netflix, había un horario sagrado donde nadie llamaba, nadie visitaba y la calle quedaba más vacía que cola de banco un domingo.'),
  ('roja', 'Espanto', 'El Diablo de Yare', 'Baila con máscara y traje rojo el día de Corpus Christi y al final se arrodilla ante el Santísimo. El único diablo que respeta el horario de misa.'),
  ('roja', 'Personajes', 'Wuilker Faríñez', 'El arquero milagro de la Vinotinto. Tapa todo menos las ganas del país de clasificar a un Mundial.'),
  ('roja', 'Comida', 'Los suspiros que se deshacen en la boca', 'Azúcar batida con aire vendida como postre. Comes uno y te quedan los dientes pidiendo perdón.'),
  ('roja', 'Objetos', 'El trompo con la púa gastada', 'Bailaba como campeón en el patio hasta que se le dobló la punta. Ahora gira chueco pero igual lo defiendes con tu vida.'),
  ('roja', 'Lugares', 'El terminal de pasajeros', 'Caos organizado: gritos de ''Valencia, Valencia, Valencia'', vendedores de chicles, maletas amarradas con mecate y un bus que sale ''ya mismito'' desde hace dos horas.'),
  ('roja', 'Evento', 'El día que sube el dólar y baja el ánimo', 'Te despiertas, abres el monitor paralelo y ya sabes que ese día comes sin lujo.'),
  ('roja', 'Dichos', '"Estar como el perro de las dos tortas"', 'No decidirte entre dos opciones y terminar quedándote sin ninguna de las dos.'),
  ('roja', 'Personajes', 'El que se queda hablando en la puerta', 'Dijo «bueno, ya me voy» hace cuarenta minutos y todavía está parado contándote la novela de su prima.'),
  ('roja', 'Guachafitas', 'El que cuenta el chiste y se ríe solo antes del final', 'El comediante que se arruina su propio remate. Lleva diez minutos riéndose y todavía nadie ha entendido nada.'),
  ('roja', 'Musica', 'Topacio', 'La protagonista ciega que hizo que tu abuela perdonara cualquier cosa con tal de que el galán por fin se diera cuenta.'),
  ('roja', 'Espanto', 'La Sayona de la carretera', 'Hermosa dama que pide la cola de noche y al subirse muestra un colmillo de menos y un mensaje para los maridos infieles. Punto de control vehicular del más allá.'),
  ('roja', 'Personajes', 'Soledad Bravo', 'La voz de la canción de protesta venezolana. Cantaba con un sentimiento que despertaba hasta al que dormía en misa.'),
  ('roja', 'Comida', 'Las polvorosas que te ahogan', 'La galleta más seca del universo. Deliciosa, pero no intentes comerla sin un vaso de agua al lado o pasas pena.'),
  ('roja', 'Objetos', 'La metra ''culebra''', 'La metra grande y bonita que ganabas y jamás apostabas. Vivía en el bolsillo como talismán de la suerte.'),
  ('roja', 'Lugares', 'La farmacia que tiene de todo menos lo que buscas', 'Encuentras perfume, chocolates, peluches, juguetes y hasta una licuadora. ¿La pastilla que necesitas? ''Ay, mi amor, esa justo se acabó.'''),
  ('roja', 'Evento', 'Comprar por encargo a la que «trae cosas de Miami»', 'La economía informal más confiable del país. Te trae hasta los repuestos del carro en la maleta de mano.'),
  ('roja', 'Dichos', '"Salir con un domingo siete"', 'Aparecerte con una sorpresa terrible y fuera de lugar, generalmente un embarazo no planificado o una deuda olvidada.'),
  ('roja', 'Personajes', 'La reina de belleza del pueblo', 'Camina por la plaza como si fuera la pasarela del Miss Venezuela, saludando con la mano de la realeza.'),
  ('roja', 'Guachafitas', 'Vestirse completo de la marca pirata del mercado de Quinta Crespo', 'El «Nike» con la palomita pa''l lado contrario y el «Adidas» de cuatro rayas. Marca propia, orgullo nacional.'),
  ('roja', 'Musica', 'Cristal', 'La novela donde aprendimos que toda venezolana de bien tiene una madre perdida, un secreto y un final feliz que tardó 200 capítulos.'),
  ('roja', 'Espanto', 'El Muerto que pide la cola', 'Lo recoges en plena oscuridad, conversa contigo lo más normal y al llegar al cementerio se baja sin pagar el pasaje. Pasajero fantasma con saldo eterno en cero.'),
  ('roja', 'Personajes', 'Yordano', 'El italiano que cantaba en español más romántico que un mensaje de buenos días con foto de flor y gif.'),
  ('roja', 'Comida', 'Una Susy a temperatura ambiente', 'El chocolate que se derretía en la lonchera y manchaba el cuaderno. Sabor a infancia y a regaño de la maestra.'),
  ('roja', 'Objetos', 'El papagayo de bolsa plástica', 'Hecho con palitos, bolsa y cabuya en plena Semana Santa. Volaba mejor que cualquier cometa comprada, palabra de honor.'),
  ('roja', 'Lugares', 'El centro comercial con aire acondicionado polar', 'El refugio nacional contra la calor. Entras a sudar afuera y adentro te congelas tanto que tienes que comprar un suéter que no necesitabas.'),
  ('roja', 'Evento', 'La pichirre que cobra hasta el hielo en su fiesta', 'Te invita, pero el ron lo pones tú, el pasapalo lo traes tú, y el hielo lo vendes por cubito.'),
  ('roja', 'Dichos', '"Pagar el pato"', 'Cargar con la culpa de algo que ni siquiera hiciste, usualmente porque eras el más cercano cuando reventó.'),
  ('roja', 'Personajes', 'El taxista filósofo', 'Te lleva del punto A al B y de paso te resuelve la crisis del país, el sentido de la vida y por qué tu equipo va perdiendo.'),
  ('roja', 'Guachafitas', 'Tener el control remoto envuelto en una bolsa de pan', 'La tecnología sagrada de la sala. Nadie sabe por qué, pero todos respetan el plástico amarillento desde 1998.'),
  ('roja', 'Musica', 'Kassandra', 'La gitana que conquistó hasta a los Balcanes: dicen que detuvo una guerra porque todos querían saber el final. Soft power criollo puro.'),
  ('roja', 'Espanto', 'La luz que se mueve en el cementerio', 'Esa lucecita que flota entre las tumbas y que tu tía jura que es un alma penando. La ciencia dice que es fósforo; tu tía dice que la ciencia no sabe nada.'),
  ('roja', 'Personajes', 'Franco De Vita', 'Compositor de baladas que sonaban en cada quinceañero y en cada despecho post-ruptura del país.'),
  ('roja', 'Comida', 'Una Cocosette mordida en el recreo', 'La galleta de coco que cambiabas por la merienda de otro. La economía escolar giraba alrededor de ella.'),
  ('roja', 'Objetos', 'La caja de pollo convertida en gallinero', 'Reciclaje criollo nivel experto: hoy cargó pollo congelado, mañana es jaula, pasado es maceta y al final, leña para la parrilla.'),
  ('roja', 'Lugares', 'La parada del autobús bajo el sol', 'El purgatorio del transporte público. No hay techo, no hay sombra, no hay bus, pero sí hay un señor que jura que ''ya viene, ya viene''.'),
  ('roja', 'Evento', 'El domingo de plancha familiar después de la rumba', 'Todos tirados en el mueble, el ventilador a máxima potencia y nadie con fuerzas ni para pedir agua.'),
  ('roja', 'Dichos', '"Estar más pelado que rodilla de chivo"', 'Nivel de quiebra tan profundo que ni la imagen del chivo alcanza para describirlo.'),
  ('roja', 'Personajes', 'El que se cuela en la fiesta', 'Nadie sabe quién lo invitó, pero ya está en la cocina sirviéndose whisky y bailando con la tía del cumpleañero.'),
  ('roja', 'Guachafitas', 'El que arregla la antena moviéndose por toda la sala hasta que «se ve»', 'El sacrificio del espectador: tienes que quedarte parado en un pie como flamenco para que no se vaya la señal del béisbol.'),
  ('roja', 'Musica', 'Por Estas Calles', 'La novela que se parecía tanto a la realidad que ya no sabías si estabas viendo la tele o asomándote por la ventana.'),
  ('roja', 'Espanto', 'El encanto de la laguna', 'Dicen que en el fondo hay una sirena que se lleva a los que nadan solos. Por eso tu mamá no te dejaba meterte después de comer, no era por la digestión.'),
  ('roja', 'Personajes', 'Karina', '''Sálvame, sálvame'', cantaba mientras nosotros también pedíamos que nos salvaran de la cola del pasaporte.'),
  ('roja', 'Comida', 'Un Toronto que te regalan el 24', 'El bombón de la ''cesta navideña'' que se reparte por compromiso. Nadie compra una caja para sí mismo, pero todos la comen.'),
  ('roja', 'Objetos', 'El koala (la riñonera) del bachaquero', 'Banco ambulante amarrado a la cintura. Adentro: efectivo, el celular, los caramelos del vuelto y los secretos de la economía paralela.'),
  ('roja', 'Lugares', 'El estacionamiento del ''centro''', 'Donde el parquero apareció de la nada con un trapo rojo, te ''cuidó'' el carro sin que se lo pidieras y ahora te cobra como si fuera valet de hotel.'),
  ('roja', 'Evento', 'La cola para echar gasolina que dura toda la noche', 'Llevas cobija, termo de café y un vecino nuevo de cola. Para cuando llegas a la bomba ya son compadres.'),
  ('roja', 'Dichos', '"Coger los corotos"', 'Agarrar tus cosas e irte molesto de un lugar, idealmente con un portazo épico de despedida.'),
  ('roja', 'Personajes', 'El abuelo que cuenta la misma historia', 'Te narra por décima vez cómo conoció a la abuela, y tú asientes como si fuera la primera, porque lo amas.'),
  ('roja', 'Guachafitas', 'Llevar el termo de tinto al estadio como si fuera oro líquido', 'El que se mete el café de la abuela escondido para no pagar el del kiosco. Sale más caro el sustento que la entrada.'),
  ('roja', 'Musica', 'La Dama de Rosa', 'Donde Jeannette Rodríguez sufría con una elegancia que tu mamá intentaba imitar incluso para ir a comprar el pan.'),
  ('roja', 'Espanto', 'El espíritu burlón del caserío', 'Te esconde el sombrero, te apaga la vela y se ríe en la esquina del cuarto. El primo molestoso del más allá, sin sangre pero con la misma maña.'),
  ('roja', 'Personajes', 'Yolanda Moreno', 'La primera bailarina de Venezuela que llevó el joropo a escenarios donde la gente ni sabía qué era una alpargata.'),
  ('roja', 'Comida', 'Una Samba de fresa', 'La que tenía la ''cremita'' en el centro y siempre se pegaba al papelito. Lujo de chuchería de los noventa.'),
  ('roja', 'Objetos', 'La bombona de gas vacía', 'El tesoro más codiciado del país. Vive afuera de la puerta esperando ''el camión'' que viene cada tres semanas o cuando Dios quiera.'),
  ('roja', 'Lugares', 'La peluquería del barrio', 'Cortan el pelo, hacen la pedicura, opinan de tu vida amorosa, te dan el chisme completo de la cuadra y bautizan al niño. Todo por el mismo precio.'),
  ('roja', 'Evento', 'El parrillero del barrio un sábado en la tarde', 'Humo, cerveza, una corneta a todo volumen y la chuleta que «ya va a estar» desde hace tres horas.'),
  ('roja', 'Dichos', '"Echarle agua al guarapo"', 'Aguar la fiesta o rebajar el entusiasmo de alguien con un comentario realista y aguafiestas.'),
  ('roja', 'Personajes', 'El mensajero de la farmacia en moto', 'Llega más rápido que una ambulancia. Si pides una pastilla, te la trae antes de que cuelgues el teléfono.'),
  ('roja', 'Guachafitas', 'El que se hace el sordo cuando le toca pagar la cuenta', 'De repente le entró una llamada importantísima, se le cayó algo debajo de la mesa y descubrió que tenía que ir al baño. Todo al mismo tiempo.'),
  ('roja', 'Musica', 'La música de la cola en la radio AM', 'Ese hilo musical entre cuñas de muebles y boletines que solo escuchas cuando llevas tres horas en el tranque y ya perdiste la fe.'),
  ('roja', 'Personajes', 'Ali Primera', 'El cantor del pueblo. Sus canciones necesarias siguen sonando más vigentes que el último aumento de pasaje.'),
  ('roja', 'Comida', 'El queso de mano recién hecho', 'Suave, salado y doblado como una arepa. Se acaba antes de llegar a la nevera porque vas ''probando''.'),
  ('roja', 'Objetos', 'El tanque de agua en el techo', 'El medidor de tu felicidad. Si está lleno, eres millonario; si suena a hueco cuando lo golpeas, prepárate para el tobo.'),
  ('roja', 'Lugares', 'El liceo público', 'Donde aprendiste más en el receso que en el aula. Sede de la fórmula del Sandwich del kiosco, el primer amor y la falta de profesor en la última hora.'),
  ('roja', 'Evento', 'La novena de aguinaldos en el colegio', 'Nueve días cantando frente al pesebre mientras esperas el chocolate caliente y el pan de jamón del final.'),
  ('roja', 'Dichos', '"Quedar como un zapato"', 'Pasar la pena más grande frente a todo el mundo, sin posibilidad de recuperar la dignidad.'),
  ('roja', 'Personajes', 'El que vende cualquier cosa en el semáforo', 'Cargadores, mandarinas, agüita, peluches, periódico, una idea de negocio... todo cabe en una luz roja.'),
  ('roja', 'Guachafitas', 'Mandar audios de cinco minutos para decir «ok»', 'El que convierte un «sí» en un podcast con introducción, desarrollo, conclusión y un «¿aló? ¿me escuchaste?» al final.'),
  ('roja', 'Musica', 'El llamado «¡Bomba!» del locutor de fiesta', 'El grito que anuncia que la canción romántica viene cargada, para que sueltes a tu pareja o la abraces más fuerte, según el caso.'),
  ('roja', 'Personajes', 'Gualberto Ibarreto', 'El oriental de la voz dulce que cantaba a las playas de Margarita que ya no podemos pagar.'),
  ('roja', 'Comida', 'La nevera llena de envases de mantequilla con sobras', 'Abres uno buscando mantequilla y encontras caraotas de hace una semana. La caja de sorpresas más peligrosa de la casa.'),
  ('roja', 'Objetos', 'La cauchera (la honda)', 'Arma de precisión hecha con una horqueta y una liga de cámara. Terror de los mangos ajenos y de las ventanas del vecino.'),
  ('roja', 'Lugares', 'La playa de Higuerote', 'El plan de fin de semana del caraqueño que no llegó a Margarita. Cola de tres horas para una arena prestada y un mar que ya conoces.'),
  ('roja', 'Evento', 'El patinatón navideño en la madrugada', 'Te levantas de madrugada a misa, sales a patinar en la calle cerrada y desayunas pan con tetero.'),
  ('roja', 'Dichos', '"Echar un pollo"', 'Decir un disparate enorme con toda la seguridad del mundo, generalmente en plena reunión importante.'),
  ('roja', 'Personajes', 'La señora del puesto de jugos naturales', 'Te exprime una naranja con un brazo de hierro mientras te cuenta los chismes del mercado completo.'),
  ('roja', 'Guachafitas', 'El abuelo que le baja el volumen a la novela para «ahorrar luz»', 'Economía energética inventada. Igual le baja el volumen a la radio antes de apagarla, no vaya a ser que gaste de más.'),
  ('roja', 'Musica', 'Un seis por derecho cantado a capela', 'Dos llaneros improvisando versos sobre tu vida en tiempo real, y tú rezando para que no rimen tu nombre con algo vergonzoso.'),
  ('roja', 'Personajes', 'Un Velo por el Mar... mejor: Vytas Brenner', 'El pionero del rock progresivo criollo, que mezclaba joropo con sintetizadores antes de que fuera cool.'),
  ('roja', 'Comida', 'La empanada de pabellón gigante', 'Todo el almuerzo metido dentro de una empanada. La ingeniería culinaria venezolana en su máxima expresión grasienta.'),
  ('roja', 'Objetos', 'El frasco de mayonesa relleno de caraotas', 'Ningún envase muere en Venezuela. El de mayonesa guarda caraotas, el de Nescafé guarda azúcar, y todos mienten sobre su contenido.'),
  ('roja', 'Lugares', 'Canaima', 'Tepuyes, ríos color té y saltos por todos lados. El lugar más prehistórico de Venezuela, donde uno espera ver un dinosaurio asomarse en cualquier momento.'),
  ('roja', 'Evento', 'La caraota refrita del desayuno', 'Lo que sobró de la cena, ahora frito con queso encima. La reencarnación más sabrosa de la cocina criolla.'),
  ('roja', 'Dichos', '"Estar en olla de grillos"', 'Encontrarte en medio de un desorden total donde todos hablan y nadie se entiende.'),
  ('roja', 'Personajes', 'El que se mete en discusiones ajenas en Twitter', 'Defiende equipos, partidos y artistas que ni le pagan, peleando con desconocidos a las 2:00 a.m.'),
  ('roja', 'Guachafitas', 'Comprar el pollo entero y pelearse en la mesa por la rabadilla', 'La parte más fea del pollo es la más peleada del país. Hay familias divididas desde tiempos de Pérez Jiménez por ese pedacito.'),
  ('roja', 'Musica', 'El órgano del señor de la cantina', 'Teclado con ritmo automático, voz de despecho y un repertorio donde todo termina en bolero. La banda sonora oficial del último trago.'),
  ('roja', 'Personajes', 'Desorden Público', 'La banda de ska que lleva décadas tocando ''Allá cayó'' mientras aquí todo sigue cayendo.'),
  ('roja', 'Comida', 'Los pasteles andinos de la parada', 'Fritos, rellenos de carne y comprados en plena Trasandina con frío de montaña. Saben a viaje familiar y a curva peligrosa.'),
  ('roja', 'Objetos', 'El pote de Toddy reciclado', 'Después del chocolate viene su segunda vida eterna: guardando harina, tornillos, botones o ese ''por si acaso'' que nunca usas.'),
  ('roja', 'Lugares', 'El Hatillo', 'El pueblito colonial de moda donde vas a comer un postre carísimo, tomarte la foto en una casa de colores y comprar una artesanía que no necesitabas.'),
  ('roja', 'Evento', 'El corte de luz justo en el clímax de la novela', 'Se va la luz cuando van a revelar quién es el papá. El país entero protesta desde la oscuridad.'),
  ('roja', 'Dichos', '"Tener la sartén por el mango"', 'Estar en posición de poder y mandar en la situación. El sueño de todo suegro.'),
  ('roja', 'Personajes', 'El pana que organiza el viaje pero nunca confirma', 'Hizo el grupo de WhatsApp, puso la fecha, mandó la cotización... y al final no fue ni él.'),
  ('roja', 'Guachafitas', 'El que se baña con la lámpara del teléfono porque se fue la luz', 'Multitasking de la oscuridad: enjabonarse, alumbrar y rezar que no se caiga el celular en el tobo, todo a la vez.'),
  ('roja', 'Musica', 'Sonido Caracas en el carrito por puesto', 'Bajo tan fuerte que las ventanas vibran y tú llegas a tu destino con el corazón latiendo al compás del reguetón ajeno.'),
  ('roja', 'Personajes', 'Caramelos de Cianuro', 'El rock nacional que sonaba en cada fiesta de liceo. ''Las Estrellas'' todavía suena en la rumba del cuarentón.'),
  ('roja', 'Comida', 'El pernil navideño', 'La estrella de la cena del 24 que el tío ''cuida'' toda la tarde con un cuchillo en la mano. Que Dios proteje al que llegue tarde.'),
  ('roja', 'Objetos', 'La lata de galletas con costura', 'La trampa más cruel de toda abuela: abres esperando galletas y adentro hay agujas, hilos y un dedal. Decepción garantizada.'),
  ('roja', 'Lugares', 'La cima del Pico Bolívar', 'El punto más alto del país. Pocos llegan, todos presumen y casi nadie aguanta el frío sin parecer un tequeño congelado.'),
  ('roja', 'Evento', 'La pelea por el control remoto del béisbol', 'La sala dividida entre Caracas y Magallanes, y la abuela exigiendo ver su telenovela en pleno noveno inning.'),
  ('roja', 'Dichos', '"Más viejo que el frío"', 'Algo o alguien con una antigüedad imposible de calcular, como el chiste que tu tío repite cada Navidad.'),
  ('roja', 'Personajes', 'El que se baña los domingos por la mañana cantando', 'Convierte la regadera en el Teresa Carreño y la cuadra entera sufre su repertorio de baladas despechadas.'),
  ('roja', 'Guachafitas', 'Decir «ya casi llego» desde la cama sin haberse levantado', 'El que mide las distancias en mentiras. Está a una hora pero en su cabeza ya está parqueando frente a tu casa.'),
  ('roja', 'Musica', 'El himno del equipo sonando en el estadio', 'Treinta mil personas desafinando juntas con tal sentimiento que de repente ganar el juego pasa a segundo plano.'),
  ('roja', 'Personajes', 'Nelson Arrieta', 'El gaitero zuliano que en diciembre suena en cada centro comercial junto al olor a hallaca y a deuda navideña.'),
  ('roja', 'Comida', 'El pan de jamón con pasas y aceitunas', 'El campo de batalla decembrino: la mitad lo ama, la otra mitad le quita las pasas con cirugía de precisión.'),
  ('roja', 'Objetos', 'El secador de pelo usado como soplador de parrilla', 'Cuando el carbón no prende, el ingenio criollo no descansa. Para eso sirve el secador viejo de tu hermana.'),
  ('roja', 'Lugares', 'El abasto a las once de la noche', 'El milagro de la cuadra: justo cuando se te acabó el papel tualé o la cerveza, ahí está, con la santamaría a medio cerrar pero dispuesto a salvarte.'),
  ('roja', 'Evento', 'El despecho con botella en mano y vallenato', 'Te dejaron, así que pones a Diomedes a todo volumen y le explicas tu vida al ventilador.'),
  ('roja', 'Dichos', '"Dar la cara"', 'Asumir la responsabilidad cuando todo se complicó, acto de honor casi extinto.'),
  ('roja', 'Personajes', 'El que se acuesta en la grama del parque a las 6 a.m.', 'Hace ejercicio una vez al año, se toma una foto estirando y desaparece hasta el próximo 1 de enero.'),
  ('roja', 'Guachafitas', 'El que le echa la culpa al perro de los ruidos en la cama', '«Fue Firulais», jura con la cara más seria del mundo, mientras el perro lo mira como diciendo «yo ni estaba aquí, mano».'),
  ('roja', 'Musica', 'La gaita que le hicieron a la maestra del colegio', 'Porque en diciembre todo el mundo merece su propia gaita: la maestra, el portero y hasta el perro de la esquina.'),
  ('roja', 'Personajes', 'Ricardo Aguirre', '''El Monumental de la Gaita''. La ''Grey Zuliana'' suena en cada hogar maracucho como himno religioso de la chinita.'),
  ('roja', 'Comida', 'La ensalada de gallina de diciembre', 'Papa, pollo y mayonesa en cantidades industriales. Hecha en una ponchera del tamaño de un lavamanos.'),
  ('roja', 'Objetos', 'El cauchito de la lavadora amarrado al portón', 'Sistema de seguridad nivel barrio: una liga gruesa que mantiene el portón cerrado mejor que cualquier candado importado.'),
  ('roja', 'Lugares', 'La cola del cajero automático', 'Una fila de fe ciega. Cuando por fin te toca, el cajero dice ''fuera de servicio'' o suelta dos billetes que no alcanzan ni para el pasaje.'),
  ('roja', 'Evento', 'El mototaxi esquivando huecos como en un videojuego', 'Te agarras como puedas, cierras los ojos y rezas. Él conoce cada hueco de la ciudad como tu mamá conoce tus mentiras.'),
  ('roja', 'Dichos', '"Estar entre la espada y la pared"', 'Atrapado entre dos opciones malas, sin escape posible, como cuando tu mamá y tu novia pelean.'),
  ('roja', 'Personajes', 'El que se sabe toda la novela', 'Te cuenta el final antes de que la veas y se ofende si no te emociona tanto como él con el villano.'),
  ('roja', 'Guachafitas', 'Guardar el dinero en la media o en el sostén en vez del banco', 'La banca privada más segura de Venezuela. Cero comisiones, máxima confianza y huele a victoria al final del día.'),
  ('roja', 'Musica', 'Un bolero a la medianoche con luz de vela', 'Romántico hasta que recuerdas que la vela está prendida porque, otra vez, se fue la luz a mitad de la canción.'),
  ('roja', 'Personajes', 'Guaco', 'La ''Superbanda'' que lleva 60 años sonando y todavía no sabemos cuántos integrantes tiene exactamente.'),
  ('roja', 'Comida', 'El ponche crema casero', 'El trago navideño que parece inofensivo hasta que llevas tres y estás bailando gaita encima de la mesa.'),
  ('roja', 'Objetos', 'La sábana de Hello Kitty del tío de 50 años', 'Nadie sabe cómo llegó ahí, pero es la más fresquita y el tío la defiende sin vergüenza alguna.'),
  ('roja', 'Lugares', 'El kiosco de revistas y chucherías', 'El mini-supermercado de la acera. Vende cigarros sueltos, chicles, recargas, periódicos viejos y consejos no solicitados sobre el país.'),
  ('roja', 'Evento', 'La caída de la señal del cable en pleno juego', 'Bases llenas, dos outs, y la pantalla se congela. El grito se escucha en todo el edificio.'),
  ('roja', 'Dichos', '"Echarse el muerto"', 'Asumir la culpa de un problema ajeno por solidaridad, lealtad o pura mala suerte.'),
  ('roja', 'Personajes', 'La maestra de preescolar', 'Santa con paciencia infinita que aguanta cuarenta carajitos, tres mocos y un vómito al día, y todavía sonríe.'),
  ('roja', 'Guachafitas', 'El que pone la silla en la cola para «guardar el puesto» y desaparece', 'El fantasma de la fila. Dejó una silla plástica, un paraguas y un primo de testigo, y volvió tres horas después como si nada.'),
  ('roja', 'Musica', 'El joropo del acto cultural escolar', 'Liquilique alquilado, falda con vuelos y un niño que se sabía el zapateo mejor que las tablas de multiplicar.'),
  ('roja', 'Personajes', 'Maelo Ruiz... no, Felipe Pirela', '''El Bolerista de América'', maracucho de voz tan suave que enamoraba hasta a la suegra más arrecha.'),
  ('roja', 'Comida', 'Las hallacas que sobran hasta febrero', 'Se congelan ''para después'' y aparecen en marzo escondidas detrás del hielo. La que nunca se acaba.'),
  ('roja', 'Objetos', 'El cooler azul con la tapa rota', 'El alma de toda playa, río y sancocho. Pierde el hielo en dos horas pero igual lo cargas porque es tradición familiar.'),
  ('roja', 'Lugares', 'La carnicería del barrio', 'Donde el carnicero te conoce, te ''rebaja'' el cuerito de la pierna pero te pesa la grasa, y siempre tiene ''algo especial pa'' usted, doña''.'),
  ('roja', 'Evento', 'El sobón que te pasa el brazo por encima en el metro', 'Vagón repleto, calor de horno, y un desconocido más pegado que tu sombra.'),
  ('roja', 'Dichos', '"Calentar la oreja"', 'Susurrarle a alguien chismes o malas ideas hasta convencerlo de algo que no quería hacer.'),
  ('roja', 'Personajes', 'El que llega a la reunión solo a comer', 'No pone un bolívar para la torta, pero es el primero en la mesa pidiendo «córtame un pedazo grande».'),
  ('roja', 'Guachafitas', 'Manejar la moto con toda la familia y el mercado encima', 'Cinco personas, un perro, dos bolsas y un coroto amarrado con mecate. La física se rinde ante el ingenio del motorizado.'),
  ('roja', 'Musica', 'La cuña pegajosa que no te puedes sacar de la cabeza', 'Esa tonadita de una marca de jabón o malta que llevas tarareando 30 años sin haber comprado el producto jamás.'),
  ('roja', 'Personajes', 'Trino Mora', 'El pionero del rock en español en Venezuela, cuando rockear era casi un acto de rebeldía nacional.'),
  ('roja', 'Comida', 'Un tinto negrito en la oficina', 'El cafecito que reúne a todo el departamento alrededor del termo. Más chisme se hace ahí que trabajo en todo el día.'),
  ('roja', 'Objetos', 'El termómetro de mercurio que se sacude', 'Antes de medirte la fiebre había que sacudirlo como maraca. Si se caía y se rompía, jugabas con las bolitas plateadas. Travesura tóxica.'),
  ('roja', 'Lugares', 'El Centro de Caracas (casco histórico)', 'Plaza Bolívar, palomas, buhoneros y el ruido de tres siglos de historia. Donde los próceres bajan del caballo de bronce a quejarse de la cola.'),
  ('roja', 'Evento', 'La feria del pueblo con calesita y algodón de azúcar', 'Luces de colores, música a todo volumen y un toro mecánico que nadie aguanta más de tres segundos.'),
  ('roja', 'Dichos', '"Estar como caballo de coleo"', 'Andar nervioso, alborotado y sin control, listo para salir corriendo en cualquier momento.'),
  ('roja', 'Personajes', 'El fanático del béisbol que insulta al televisor', 'Grita instrucciones al mánager como si lo escuchara y jura que él lo haría mejor desde el mueble.'),
  ('roja', 'Guachafitas', 'El que se sabe la letra del himno cambiada por groserías desde el liceo', 'Patrimonio cultural inmaterial. La versión «oficial» del recreo que todavía se le escapa en los actos del 5 de julio.'),
  ('roja', 'Musica', 'El despecho de Pasta Base… digo, de bar de pueblo', 'Cuando el rocolo escupe una de esas canciones donde el tipo perdió a la mujer, el carro y la dignidad, todo en la misma estrofa.'),
  ('roja', 'Personajes', 'Corina Smith', 'La cantante pop que pasó de YouTube a los escenarios, demostrando que el talento criollo sí emigra para arriba.'),
  ('roja', 'Comida', 'Una empanada de carne mechada en la playa', 'Caliente, grasienta y servida en una servilleta que se transparenta. El desayuno de quien madrugó para agarrar puesto.'),
  ('roja', 'Objetos', 'La plancha de hierro fundido', 'La que se calentaba en la cocina y pesaba un kilo. Tu abuela la usaba y de paso ejercitaba el brazo. Indestructible como ella.'),
  ('roja', 'Lugares', 'El estadio Universitario', 'Catedral del beisbol criollo. Caracas vs Magallanes, cerveza tibia, hot dog con todo y un narrador interno que se sabe el nombre de todo el mundo.'),
  ('roja', 'Evento', 'El primer aguacero que inunda toda la calle', 'Llovió diez minutos y ya la avenida es un río. Los carros flotan y los muchachos se bañan en la esquina.'),
  ('roja', 'Dichos', '"Meter la pata hasta el fondo"', 'Equivocarte no como un error sencillo, sino como una obra maestra de la metida de pata.'),
  ('roja', 'Personajes', 'El que arregla todo con alambre y teipe', 'Mecánico, plomero, electricista y carpintero sin título. Si se rompe, él lo «arregla» hasta que se vuelva a romper.'),
  ('roja', 'Guachafitas', 'Echarse perfume encima en vez de bañarse cuando se va el agua', 'La ducha seca nacional. Tres rociadas de colonia barata y un desodorante con fe, y pa''la calle como si nada.'),
  ('roja', 'Musica', 'Música de chinchorro un domingo de resaca', 'Salsa romántica suave, ventilador girando y la promesa de que hoy no se hace absolutamente nada más que mecerse.'),
  ('roja', 'Personajes', 'Lasso', '''Ojalá'' la dedicaste a alguien que ya ni se acuerda de ti, pero la canción sigue pegando.'),
  ('roja', 'Comida', 'El sándwich de mortadela del recreo', 'Pan blanco, mortadela y nada más. El lujo de quien no le quedaba para la cantina, pero igual sabroso.'),
  ('roja', 'Objetos', 'El radio de pilas que solo agarra una emisora', 'Compañero fiel del apagón. Da igual lo que quieras oír: solo pega esa emisora de música llanera con interferencia incluida.'),
  ('roja', 'Lugares', 'La cola del peaje', 'Donde se forma la procesión nacional un día feriado. Avanzas un metro cada media hora y siempre hay alguien que se mete en cola con cara de inocente.'),
  ('roja', 'Evento', 'La visita médica de la tía que llega con remedios caseros', 'Para todo tiene una hoja, un brebaje o un té amargo. «Tómate esto y verás que se te quita».'),
  ('roja', 'Dichos', '"Sacarle el cuerpo"', 'Esquivar una responsabilidad o a una persona con la elegancia de un torero asustado.'),
  ('roja', 'Personajes', 'La doña que vende dulces criollos en la ventana de su casa', 'Jalea de mango, conserva de coco y besitos de coco. Su cocina huele a infancia y a papelón.'),
  ('roja', 'Guachafitas', 'El que pide la cuenta «dividida» y empieza a sacar la calculadora del impuesto', 'El contador de la mesa. «Yo solo me tomé dos refrescos», dice el que se comió tres parrillas y un postre.'),
  ('roja', 'Musica', 'El cañonazo de fin de año en la radio', 'Esa lista de éxitos que solo existe para que el 31 de diciembre brindes con gente que no veías desde el cañonazo anterior.'),
  ('roja', 'Personajes', 'Micro TDH', 'El urbano que canta del amor y el desamor mientras tú haces playback frente al espejo.'),
  ('roja', 'Comida', 'Un raspado de cola con leche condensada', 'Hielo, sirope rojo fosforescente y un chorro de leche que lo hace ''gourmet''. Te pinta la lengua y la conciencia.'),
  ('roja', 'Objetos', 'El paragüero hecho con un tobo viejo', 'Decoración criolla en la entrada. Antes cargaba agua, ahora carga paraguas rotos que nadie va a arreglar jamás.'),
  ('roja', 'Lugares', 'La playa de Cata', 'El postalita de Aragua: media luna de arena, palmeras y un mar bravo que te revuelca dos veces antes de dejarte salir con respeto.'),
  ('roja', 'Evento', 'El domingo de misa, almuerzo y siesta sagrada', 'La trinidad del descanso criollo. Después de la siesta, nadie es responsable de sus actos.'),
  ('roja', 'Dichos', '"Estar guayabo"', 'Andar nostálgico y triste por un amor perdido, idealmente con vallenato de fondo.'),
  ('roja', 'Personajes', 'El pana que se duerme en toda fiesta', 'A las 11 ya está roncando en el mueble con el plato en la mano, mientras la rumba apenas empieza.'),
  ('roja', 'Guachafitas', 'Usar la franela vieja como trapo, pijama y luego de gala según la ocasión', 'La franela camaleón. Empezó siendo de salir, pasó a dormir, terminó secando el carro y todavía respira.'),
  ('roja', 'Musica', 'Un tema de Yordano para llorar con elegancia', 'Cuando quieres sufrir, pero con clase y buena producción, sin caer en el despecho de cantina barata.'),
  ('roja', 'Personajes', 'Big Soto', 'El trapero criollo que rapea de billetes verdes que aquí solo vemos en sueños y en el paralelo.'),
  ('roja', 'Comida', 'La tizana en el cumpleaños', 'Un mar de frutas picadas nadando en jugo dulce. El postre y la bebida en un solo vaso, servido con un cucharón.'),
  ('roja', 'Objetos', 'La bicicleta ''cross'' sin frenos', 'Se frenaba con la suela del zapato o contra la pared del vecino. Tenía pegatinas, mechones de colores y cero seguridad.'),
  ('roja', 'Lugares', 'El centro comercial Sambil', 'Templo del consumo, punto de encuentro y refugio del aire acondicionado. ''Nos vemos en el Sambil'' es una dirección válida en todo el país.'),
  ('roja', 'Evento', 'La rifa del trabajo que nunca entrega el premio', 'Compraste diez números «por colaborar» y el premio se lo ganó la sobrina de la organizadora. Qué casualidad.'),
  ('roja', 'Dichos', '"Echar leña al fuego"', 'Empeorar deliberadamente una pelea ajena por puro entretenimiento. Aporte clásico del primo metiche.'),
  ('roja', 'Personajes', 'El que maneja con una mano y come con la otra', 'Hamburguesa en una mano, teléfono entre el hombro y la oreja, y todavía te toca corneta por ir lento.'),
  ('roja', 'Guachafitas', 'El que pregunta «¿y eso qué es?» en el menú y termina pidiendo lo de siempre', 'Estudió la carta entera, le preguntó al mesonero por cada plato sofisticado y al final pidió pollo con tajadas. Como siempre.'),
  ('roja', 'Musica', 'La salsa que pone el vecino a las 6 a.m. del sábado', 'Su derecho a celebrar la vida con El Gran Combo a todo volumen pesa más que tu derecho a dormir hasta tarde un solo día.'),
  ('roja', 'Personajes', 'Danny Ocean', '''Me rehúso'' a aceptar que ya pasaron años de esa canción y que media diáspora la lloró en algún aeropuerto.'),
  ('roja', 'Comida', 'El pollo en brasa del domingo', 'Con sus papas y su ensalada de col bañada en salsa rosada. El almuerzo de quien no quiso cocinar y nadie lo juzga.'),
  ('roja', 'Objetos', 'El abrigo que solo se usa una vez al año en Mérida', 'Vive en el fondo del closet esperando ese único viaje al páramo. El resto del año es testigo mudo de tu sudor.'),
  ('roja', 'Lugares', 'La cola para echar gasolina', 'El campamento más largo del país. La gente lleva silla, comida, abanico y hasta se hace amiga del de adelante. Acampar mientras el tanque sueña.'),
  ('roja', 'Evento', 'El profesor que llega tarde pero igual pasa lista', 'Entra a los cuarenta minutos, no da clase, pero le importa muchísimo saber quién faltó.'),
  ('roja', 'Dichos', '"Estar más limpio que talón de lavandera"', 'Sin un solo billete, brillando de pura pobreza. La metáfora más criolla de la quiebra.'),
  ('roja', 'Personajes', 'El locutor de radio AM de la madrugada', 'Voz de terciopelo que dedica baladas a doña Carmen de Petare y manda saludos a todo el este del país.'),
  ('roja', 'Guachafitas', 'Tener una matica sembrada en una lata de leche Klim oxidada', 'El jardín botánico del balcón criollo. Ahí crece sábila, orégano orejón y una bendición que dejó la vecina antes de mudarse.'),
  ('roja', 'Personajes', 'Catherine Fulop', 'La actriz que conquistó Argentina y ahora es más argentina que el dulce de leche, pero sigue diciendo ''chamo''.'),
  ('roja', 'Comida', 'Las arepas fritas con queso amarillo', 'Cuando no hay budare o hay flojera, se fríen. Quedan crujientes por fuera, peligrosas para el colesterol y deliciosas.'),
  ('roja', 'Objetos', 'La franela de la promoción que ya no te queda', 'Reliquia del liceo que guardas por nostalgia. Te quedaba flojita en 5to año y hoy no te pasa de los hombros.'),
  ('roja', 'Lugares', 'El barrio 23 de Enero', 'Los bloques más famosos de Caracas, con escaleras infinitas, historia política a flor de piel y una vista de la ciudad que cuesta cada peldaño.'),
  ('roja', 'Evento', 'La cola para sacar el pasaporte que parece interminable', 'Un trámite que te envejece. Pides cita, te dan para dentro de un año, y aún así llegas y no apareces en el sistema.'),
  ('roja', 'Dichos', '"Hacerle el feo a la comida"', 'Despreciar un plato delante de quien lo cocinó, pecado mortal en cualquier casa venezolana.'),
  ('roja', 'Personajes', 'El que se cree DJ con la corneta del carro', 'Baja todas las ventanas para que el barrio sepa que tiene buen gusto musical. Spoiler: no lo tiene.'),
  ('roja', 'Guachafitas', 'El que se duerme en la película y jura que «solo cerró los ojos un ratico»', 'Roncó toda la trama, se perdió el final y pregunta «¿y entonces quién era el malo?» con todo el descaro del mundo.'),
  ('roja', 'Personajes', 'Ruddy Rodríguez', 'La galana de las novelas de los 90 por la que medio país llegaba temprano a la casa para ver el capítulo.'),
  ('roja', 'Comida', 'El perico para el desayuno', 'Huevos revueltos con tomate y cebolla, el desayuno que se hace en cinco minutos. Acompaña arepa, pan o lo que aparezca.'),
  ('roja', 'Objetos', 'El vaso de Mickey Mouse del McDonald''s', 'Coleccionable noventero que ascendió a vajilla oficial de la casa. Para tomar agua, jugo y hasta el guarapo de tu abuela.'),
  ('roja', 'Lugares', 'La lavandería del barrio', 'Donde dejas la ropa y rezas para que no te la cambien por la del vecino. La señora siempre te dice ''mañana a las dos'' y nunca está lista a las dos.'),
  ('roja', 'Evento', 'El pana que pide la cola y termina manejando él', 'Empezó pidiéndote el aventón y al final tú vas de copiloto en tu propio carro.'),
  ('roja', 'Dichos', '"Llevarse a alguien por delante"', 'Atropellar a la gente, literal o figuradamente, por andar apurado y sin mirar a nadie.'),
  ('roja', 'Personajes', 'La señora que reza el rosario en el autobús', 'Encomienda el viaje completo a todos los santos porque conoce al chofer y sabe cómo maneja.'),
  ('roja', 'Guachafitas', 'Llevar la nevera de anime a la playa más llena de cervezas que de hielo', 'La logística del sol y arena: el hielo se derrite en dos horas, las cervezas se calientan y igual se las toman como agua bendita.'),
  ('roja', 'Personajes', 'Coraima Torres', 'La ''Kassandra'' que se transmitió en 180 países. Hay gente en Serbia que aprendió español viéndola sufrir.'),
  ('roja', 'Comida', 'El casabe con suero', 'La torta crujiente de yuca que truena al partirla. Con suero salado encima es un manjar prehispánico que sigue vigente.'),
  ('roja', 'Objetos', 'La cartera de tu mamá que tiene de todo', 'Un universo paralelo: pañitos, caramelos, aspirinas, una factura del 2015, hilo, aguja y, en el fondo, las llaves que jura no encontrar.'),
  ('roja', 'Lugares', 'El Saladillo de Maracaibo', 'Cuna de la gaita y de las casas de colores. Donde todo maracucho jura que se inventó el patacón, el queso y la alegría.'),
  ('roja', 'Evento', 'La cuadra que se va la luz solo en tu casa', 'Todo el barrio con luz menos tú. Sales al frente, miras al cielo y maldices al transformador personal.'),
  ('roja', 'Dichos', '"Estar en el aire"', 'No tener nada resuelto ni decidido. Estado civil, laboral y mental del venezolano promedio.'),
  ('roja', 'Personajes', 'El que pregunta «¿y a cómo está el dólar?» en cada conversación', 'Economista de cafetín que actualiza la tasa antes que el propio paralelo y te lo dice sin que preguntes.'),
  ('roja', 'Guachafitas', 'El que arregla los lentes rotos con teipe y sigue su vida normal', 'El profesor Chiflado del barrio. Tres vueltas de teipe en la patica, una ladeadita permanente y orgullo de no haber gastado un real.'),
  ('roja', 'Personajes', 'Gabriela Spanic', '''La Usurpadora'', que jugó a la gemela buena y la gemela mala con una dedicación digna de premio.'),
  ('roja', 'Comida', 'Una catalina (paledonia) con café', 'La galleta oscura de papelón y especias, dura como piedra. Se moja en el café para que no te tumbe un diente.'),
  ('roja', 'Objetos', 'El llavero con quince llaves de puertas que ya no existen', 'Nadie sabe qué abren la mitad, pero botarlas da yeta. Pesan como un ancla y suenan a inseguridad bien guardada.'),
  ('roja', 'Lugares', 'La carretera vieja Caracas-La Guaira', 'Curvas, neblina y nostalgia. La ruta del que no quiere pagar autopista pero sí quiere marearse y ver el mar aparecer por sorpresa.'),
  ('roja', 'Evento', 'El cumpleaños sorpresa que todo el mundo sabía menos el festejado', 'Llevaban semanas planeándolo en un grupo de WhatsApp y él fue el último en enterarse... por accidente.'),
  ('roja', 'Dichos', '"Echar un cuento"', 'Narrar una anécdota tan elaborada que ni tú recuerdas qué parte fue verdad.'),
  ('roja', 'Personajes', 'El pana que se ofrece a ayudar en la mudanza y desaparece', 'Llega cuando ya subiste la nevera por las escaleras y se va apenas hay pizza repartida.'),
  ('roja', 'Guachafitas', 'Anunciar que vas a dejar de tomar todos los lunes del año', 'El propósito más reciclado de Venezuela. El lunes dura hasta que alguien dice «¿nos echamos una fría?» a las cuatro de la tarde.'),
  ('roja', 'Personajes', 'Lupita Ferrer', 'La primera actriz venezolana que abrió camino en Hollywood cuando ''soñar en grande'' era ilegal por escaso.'),
  ('roja', 'Comida', 'Los chicharrones de la carretera', 'Colgados en ganchos a la vista de todos, sin nevera y sin remordimiento. Paras, compras y rezas para que el estómago aguante.'),
  ('roja', 'Objetos', 'El espejo retrovisor amarrado con alambre', 'El carro perdió un retrovisor en 2018 y desde entonces sobrevive con alambre, oraciones y la fe del conductor.'),
  ('roja', 'Lugares', 'El abasto que fía', 'La institución financiera más confiable del barrio. ''Anótamelo en la libreta'' es un contrato de honor más serio que cualquier banco.'),
  ('roja', 'Evento', 'La cena navideña que empieza a la 1 a.m.', 'Comes la hallaca de madrugada porque la abuela «todavía no está lista» y nadie se atreve a apurarla.'),
  ('roja', 'Dichos', '"Quedarse en el sitio"', 'Sorprenderse tanto con algo que el cuerpo deja de funcionar momentáneamente.'),
  ('roja', 'Personajes', 'El que se sabe el chiste pero lo cuenta mal', 'Se ríe antes del final, se le olvida el remate y aun así espera que toda la mesa le aplauda.'),
  ('roja', 'Personajes', 'Jean Carlo Simancas', 'El galán eterno de las novelas, que enamoraba a tres generaciones de tías con una sola mirada.'),
  ('roja', 'Comida', 'Una arepa ''pelúa'' rebosada', 'Carne mechada y queso amarillo rallado por encima como melena. El nombre lo explica todo, el sabor lo justifica.'),
  ('roja', 'Objetos', 'La cornetica del Polar Ice en la cava de playa', 'El sonido que anuncia que el vendedor está cerca. Sagrado como las campanas de la iglesia, pero más bienvenido bajo el sol.'),
  ('roja', 'Lugares', 'Choroní de noche con tambores', 'Cuando el cuero del tambor suena, el pueblo entero se mueve y nadie duerme. La fiesta de San Juan que despierta hasta a los muertos.'),
  ('roja', 'Evento', 'El regateo en el mercado municipal', 'Un duelo de voluntades por dos bolívares de diferencia. Al final compras de más «porque me cayó bien».'),
  ('roja', 'Dichos', '"Ponerse las pilas"', 'Espabilarse y empezar a hacer las cosas en serio, generalmente cuando ya es demasiado tarde.'),
  ('roja', 'Personajes', 'La cajera del supermercado que pide cambio', 'Te pregunta si tienes «el sencillo» con cara de súplica, como si fuera culpa tuya que no haya monedas en el país.'),
  ('roja', 'Personajes', 'Carlos Mata', 'Galán y cantante de novela que tenía a las señoras suspirando y a los esposos celosos del televisor.'),
  ('roja', 'Comida', 'El tequeñón del centro comercial', 'El tequeño tamaño familiar que comes con cuchillo y tenedor. Caro, gigante y bañado en salsa, puro show de feria.'),
  ('roja', 'Objetos', 'El ventilador de techo que tiembla', 'Gira con un bamboleo que te quita el sueño porque crees que se va a caer encima de ti. Lleva 20 años amenazando y nunca cumple.'),
  ('roja', 'Lugares', 'El ambulatorio del barrio', 'Donde llegas a las cinco de la mañana por una ficha, te atienden a las dos de la tarde y el doctor te receta ''reposo y bastante líquido''.'),
  ('roja', 'Evento', 'El motorizado que te entrega el pedido frío', 'Pediste caliente, llegó tibio, y el delivery jura que «salió hace cinco minutos» de hace una hora.'),
  ('roja', 'Dichos', '"Estar más perdido que cochino en feria"', 'Andar completamente desorientado y rodeado de peligro, sin saber que eres el plato principal.'),
  ('roja', 'Personajes', 'El que llega de Estados Unidos hablando medio inglés', 'Pasó tres meses en Doral y ya se le olvidó cómo se dice «cola». Ahora todo es «traffic» y «el rentón».'),
  ('roja', 'Personajes', 'Amanda Gutiérrez... mejor: Hilda Carrero', 'La villana de novela perfecta: la odiabas tanto que querías meterte en el televisor a darle un correazo.'),
  ('roja', 'Comida', 'La cachapa con cochino y mantequilla derritiéndose', 'Cuando la mantequilla baja por los lados ya sabes que el día va a ser bueno. La felicidad es de color amarillo.'),
  ('roja', 'Objetos', 'El cuaderno Caribe forrado con plástico transparente', 'Útil escolar de élite. Forrarlo con la regla y sin burbujas era un arte que separaba a los pulcros de los desastres.'),
  ('roja', 'Lugares', 'La parada de los ''piratas''', 'El transporte informal de toda esquina: un carro lleno hasta el mecate, música a todo volumen y un chofer que maneja como si lo persiguieran.'),
